#include "world/runtime_compiler.h"
#include "world/individual_state.h"

int main() {
    // Create 1000 individuals with random positions
    auto world = create_test_world(1000);

    // Define a state update kernel as a string
    const char* kernel_source = R"(
        #include "world/individual_state.h"

        extern "C" __global__
        void update_positions(IndividualState* states, int n, float dt) {
            int idx = blockIdx.x * blockDim.x + threadIdx.x;
            if (idx >= n) return;

            // Simple Euler integration
            states[idx].position += states[idx].velocity * dt;

            // Wrap around world boundaries
            states[idx].position.x = fmodf(states[idx].position.x + 100.0f, 200.0f) - 100.0f;
            states[idx].position.y = fmodf(states[idx].position.y + 100.0f, 200.0f) - 100.0f;
            states[idx].position.z = fmodf(states[idx].position.z + 100.0f, 200.0f) - 100.0f;
        }
    )";

    // JIT compile
    world::RuntimeCompiler compiler;
    auto result = compiler.compile(kernel_source);

    if (!result.success) {
        std::cerr << "Compilation failed:\n" << result.error_log << std::endl;
        return 1;
    }

    std::cout << "Compiled successfully! "
              << result.register_count << " registers, "
              << result.shared_memory_bytes << " bytes shared mem\n";

    // Run 100 ticks
    for (int tick = 0; tick < 100; tick++) {
        float dt = 0.016f;  // 60Hz
        void* args[] = { &world.states_gpu, &world.num_individuals, &dt };
        compiler.launch(result, args, 
                       dim3((world.num_individuals + 255) / 256), 
                       dim3(256), 0, stream);
    }

    // Print final positions of first 5 individuals
    world.sync_to_host();
    for (int i = 0; i < 5; i++) {
        auto& s = world.states[i];
        printf("Individual %d: (%.2f, %.2f, %.2f)\n", 
               i, s.position.x, s.position.y, s.position.z);
    }
}
```

