  ├── Tick Scheduler ──diag──> DiagnosticEmitter
  ├── PubSub Transport ──diag──> DiagnosticEmitter
  ├── Individual Executor ──diag──> DiagnosticEmitter
  └── Consensus Engine ──diag──> DiagnosticEmitter
