  PubChannel,       // pub/sub publish channel
  SubChannel,       // pub/sub subscribe channel
  StateStore,       // individual state storage allocator
  Scheduler,        // tick scheduler handle
  Transport,        // DDS/RTPS transport endpoint
  GroupCache,       // group-shared state cache
  Profiler,         // performance profiler attachment
  Custom,           // user-defined resource kind
};
```

