import pubsub_loop as psl

pipeline = psl.IndividualPipeline(ipu=0, stream=stream_a)
pipeline.push(ind1)  # OK

psl.set_device(1)  # switch device

try:
    pipeline.push(ind2)  # raises WorldRuntimeError
except psl.WorldRuntimeError as e:
    print(e)
    # IndividualPipeline: active IPU (1) != bound IPU (0).
    # Did you call world::set_device() after pipeline creation?
```

