### 核心实现

#### 1. `world::std::erase` — 按值擦除

```cpp
// world/std/erase.hpp
namespace world::std {

// 从个体状态容器中擦除所有等于 value 的条目
// 对应：从世界全局状态存储中移除指定个体ID
template <typename Container, typename T>
typename Container::size_type
erase(Container& c, const T& individual_id) {
    auto it = ::std::remove(c.begin(), c.end(), individual_id);
    auto removed = ::std::distance(it, c.end());
    c.erase(it, c.end());
    return static_cast<typename Container::size_type>(removed);
}

// map/unordered_map 特化（个体ID→状态 的注册表擦除）
template <typename Key, typename T, typename Comp, typename Alloc>
typename ::std::map<Key,T,Comp,Alloc>::size_type
erase(::std::map<Key,T,Comp,Alloc>& c, const Key& individual_id) {
    return c.erase(individual_id);
}

} // namespace world::std
```

#### 2. `world::std::erase_if` — 条件擦除

```cpp
// world/std/erase_if.hpp
namespace world::std {

// 从个体状态容器中擦除满足谓词的所有个体状态
// 对应：从世界全局状态存储中批量清理失活个体
template <typename Container, typename Pred>
typename Container::size_type
erase_if(Container& c, Pred&& pred) {
    auto it = ::std::remove_if(c.begin(), c.end(),
                               ::std::forward<Pred>(pred));
    auto removed = ::std::distance(it, c.end());
    c.erase(it, c.end());
    return static_cast<typename Container::size_type>(removed);
}

// 关联容器特化（map、set、unordered_map、unordered_set）
template <typename Key, typename T, typename Comp, typename Alloc, typename Pred>
typename ::std::map<Key,T,Comp,Alloc>::size_type
erase_if(::std::map<Key,T,Comp,Alloc>& c, Pred&& pred) {
    typename ::std::map<Key,T,Comp,Alloc>::size_type removed = 0;
    for (auto it = c.begin(); it != c.end(); ) {
        if (pred(*it)) { it = c.erase(it); ++removed; }
        else           { ++it; }
    }
    return removed;
}

} // namespace world::std
```

#### 3. pub/sub循环中的实际使用

```cpp
// world/runtime/pubsub_loop.hpp
void PubSubLoop::cleanup_inactive_individuals(
    IndividualRegistry& registry,
    DdsPublisher& dds)
{
    // 个体状态归约后，批量清理失活个体
    auto removed_count = world::std::erase_if(
        registry.state_vector(),
        [](const IndividualState& s) {
            return !s.is_active() || s.is_out_of_world_bounds();
        });

    if (removed_count > 0) {
        // 通知 DDS/RTPS 取消发布
        dds.retract_inactive_individuals(registry);
        // 更新 Needle Engine GLB 渲染层
        registry.notify_render_layer(removed_count);
    }
}
```

