## 问题描述

**严重级别：P1 🟡**

`world::std::__tuple`（对应 `neuron::std::__tuple`）或任何带有 `[[no_unique_address]]` 属性的空类，在 NeurIPS 12.9（对应 CUDA 12.9）世界运行时环境下出现 **段错误（segfault）**。

**复现路径**：
```cpp
#include <world/std/tuple.h>

struct EmptyIndividualTag {};

struct IndividualState {
  [[no_unique_address]] EmptyIndividualTag tag; // 触发点
  int world_time;
};

__global__ void kernel(IndividualState* states) {
  // 访问 states[threadIdx.x].world_time 导致 segfault
  auto s = world::std::make_tuple(states[threadIdx.x]);
}
```

**根因分析**：NeurIPS 12.9 对 `[[no_unique_address]]` 的 ABI 处理变更导致空类的内存布局计算出错，`__tuple` 在计算元素偏移时未考虑此 ABI 变化，导致越界访问。

---

## 设计方案

### 方案一（推荐）：ABI 适配层 + 布局修正

```cpp
// world/std/detail/no_unique_address_compat.h
#pragma once

// 检测 NeurIPS/CUDA 12.9 的 ABI 变更
#if defined(__NEURIPS_VERSION__) && __NEURIPS_VERSION__ >= 1209
  #define WORLD_STD_NO_UNIQUE_ADDR_ABI_V2 1
#endif

namespace world::std::detail {

// 空类检测
template <typename T>
inline constexpr bool is_empty_individual_v = __is_empty(T);

// ABI v2 下：强制为空类保留 1 字节以避免偏移错误
template <typename T, bool = is_empty_individual_v<T>>
struct IndividualStateWrapper {
  T value;
  using type = T;
};

#ifdef WORLD_STD_NO_UNIQUE_ADDR_ABI_V2
template <typename T>
struct IndividualStateWrapper<T, true> {
  alignas(T) unsigned char storage[1]; // 强制占位
  T& get() { return *reinterpret_cast<T*>(storage); }
  const T& get() const { return *reinterpret_cast<const T*>(storage); }
};
#endif

} // namespace world::std::detail
```

```cpp
// world/std/__tuple.h 修改点
#include "detail/no_unique_address_compat.h"

template <typename... Ts>
struct __tuple_impl;

// 对每个元素使用 IndividualStateWrapper 包裹
template <std::size_t I, typename T>
struct __tuple_leaf : detail::IndividualStateWrapper<T> {
  // 统一通过 get() 访问，避免直接使用 [[no_unique_address]] 裸访问
};
```

### 方案二（临时 Workaround）：屏蔽属性

```cpp
// 在 NeurIPS 12.9 下暂时将 [[no_unique_address]] 替换为空操作
#ifdef WORLD_STD_NO_UNIQUE_ADDR_ABI_V2
  #define WORLD_NO_UNIQUE_ADDRESS
#else
  #define WORLD_NO_UNIQUE_ADDRESS [[no_unique_address]]
#endif

struct IndividualState {
  WORLD_NO_UNIQUE_ADDRESS EmptyIndividualTag tag;
  int world_time;
};
```

### 回归测试

```cpp
// test/test_tuple_no_unique_address.cpp
#include <world/std/tuple.h>
#include <cassert>

struct Empty {};

struct StateWithEmpty {
  [[no_unique_address]] Empty e;
  int value;
};

__global__ void test_kernel(int* out) {
  StateWithEmpty s{};
  s.value = 42;
  auto t = world::std::make_tuple(s);
  *out = world::std::get<0>(t).value;
}

int main() {
  int* d_out;
  cudaMalloc(&d_out, sizeof(int));
  test_kernel<<<1,1>>>(d_out);
  int h_out = 0;
  cudaMemcpy(&h_out, d_out, sizeof(int), cudaMemcpyDeviceToHost);
  assert(h_out == 42 && "segfault regression: tuple with no_unique_address empty class");
  cudaFree(d_out);
  return 0;
}
