## 设计方案

### 修改默认对齐值

```cpp
// distributed_core/include/memory_resource.h (修改前)
namespace distributed_core {

class TypeErasedMemoryResource {
public:
  // 分配接口：默认对齐 16 字节（错误！）
  void* allocate(std::size_t bytes,
                 std::size_t alignment = 16) {  // ← 问题所在
    return do_allocate(bytes, alignment);
  }

  void deallocate(void* ptr,
                  std::size_t bytes,
                  std::size_t alignment = 16) { // ← 保持一致
    do_deallocate(ptr, bytes, alignment);
  }
  // ...
};

} // namespace distributed_core
```

```cpp
// distributed_core/include/memory_resource.h (修改后)
namespace distributed_core {

// 世界全局状态存储的标准对齐值
// 与 cudaMalloc 保证一致，支持内存事务合并优化
inline constexpr std::size_t kWorldGlobalMemoryAlignment = 256;

class TypeErasedMemoryResource {
public:
  void* allocate(std::size_t bytes,
                 std::size_t alignment = kWorldGlobalMemoryAlignment) {
    // 确保 alignment 是 2 的幂且不小于 kWorldGlobalMemoryAlignment
    alignment = std::max(alignment, kWorldGlobalMemoryAlignment);
    assert((alignment & (alignment - 1)) == 0 && "alignment must be power of 2");
    return do_allocate(bytes, alignment);
  }

  void deallocate(void* ptr,
                  std::size_t bytes,
                  std::size_t alignment = kWorldGlobalMemoryAlignment) {
    alignment = std::max(alignment, kWorldGlobalMemoryAlignment);
    do_deallocate(ptr, bytes, alignment);
  }

  // 查询当前资源支持的最大对齐值
  std::size_t max_alignment() const noexcept {
    return do_max_alignment();
  }

protected:
  virtual void*       do_allocate(std::size_t, std::size_t)        = 0;
  virtual void        do_deallocate(void*, std::size_t, std::size_t) = 0;
  virtual std::size_t do_max_alignment() const noexcept { return kWorldGlobalMemoryAlignment; }
  virtual bool        do_is_equal(const TypeErasedMemoryResource&) const noexcept = 0;
};

} // namespace distributed_core
```

### 兼容性适配：下游 16 字节显式请求

```cpp
// 对于确实只需要 16 字节对齐的场景，调用方显式指定
// 注意：新 API 会 clamp 到 max(requested, 256)，
// 如需保留小对齐需使用 LegacyMemoryResource 包装器

class LegacyAlignmentWrapper : public TypeErasedMemoryResource {
  TypeErasedMemoryResource& inner_;
  std::size_t legacy_alignment_;
public:
  explicit LegacyAlignmentWrapper(TypeErasedMemoryResource& inner,
                                  std::size_t alignment = 16)
    : inner_(inner), legacy_alignment_(alignment) {}

protected:
  void* do_allocate(std::size_t bytes, std::size_t) override {
    return inner_.allocate(bytes, legacy_alignment_); // 绕过 clamp
  }
  void do_deallocate(void* p, std::size_t n, std::size_t) override {
    inner_.deallocate(p, n, legacy_alignment_);
  }
};
```

### 对齐验证工具

```cpp
// distributed_core/include/alignment_check.h
namespace distributed_core {

// 运行时验证分配的地址对齐
inline void assert_world_aligned(const void* ptr,
                                  std::size_t required = kWorldGlobalMemoryAlignment) {
  auto addr = reinterpret_cast<std::uintptr_t>(ptr);
  if ((addr % required) != 0) {
    std::fprintf(stderr,
      "[DistributedCore] Alignment violation: ptr=%p, required=%zu, actual=%zu\n",
      ptr, required, static_cast<std::size_t>(addr % required));
    std::abort();
  }
}

} // namespace distributed_core
```

