// 为 __device__ 代码提供轻量化的 join_view（无 optional，无虚函数）

namespace world::device::ranges {

template <typename OuterRange, typename InnerRange>
struct flat_join_view {
  OuterRange outer;

  struct iterator {
    // device 端简化实现：预先展平到连续缓冲区
    // 适用于内层 range 大小在编译期已知的场景
    __device__ auto operator*() const;
    __device__ iterator& operator++();
  };

  __device__ iterator begin() const;
  __device__ iterator end()   const;
};

} // namespace world::device::ranges
```

