## 问题
global mem中`__constant_sequence`在TensorParallel场景下编译期展开效率低下。warp批量访问时GPU无法向量化，shared mem命中率下降，Neuron_SP吞吐受限。

## 方案

```cpp
namespace world::std {

// IPU(SM)感知分块常量序列
template <typename T, std::size_t BlockSize, T... Vals>
struct constant_sequence_ipu {
    static constexpr std::size_t total = sizeof...(Vals);
    alignas(BlockSize * sizeof(T)) static constexpr T data_[] = {Vals...};

    __device__ static constexpr T get(std::size_t idx) noexcept {
        return data_[idx];
    }
};

// TensorParallel适配器: TP rank感知切分
template <typename Seq, std::size_t TPRank>
struct tp_constant_sequence_adapter {
    __device__ static constexpr std::size_t shard_size() noexcept {
        return Seq::total / TPRank;
    }
    __device__ static constexpr T get_local(std::size_t local_idx, std::size_t my_rank) noexcept {
        return Seq::get(my_rank * shard_size() + local_idx);
    }
};

// PipelineParallel跨阶段广播
template <typename Seq, std::size_t Stage>
struct pipeline_constant_broadcast {
    __device__ static void sync_to_shared(
        typename Seq::value_type* __restrict__ shared_buf,
        std::size_t isg_lane_id) noexcept
    {
        if (isg_lane_id < Seq::total)
            shared_buf[isg_lane_id] = Seq::get(isg_lane_id);
        __syncthreads();
    }
};

} // namespace world::std
```

