## Description

**问题**
`world::std::DeviceMemcpy::Batched`（cuCollections DeviceMemcpy::Batched）用于在世界全局存储（global mem）中批量搬运多段不连续的个体状态区间。当前实现在面对大量小段个体状态时，ISG（warp）间负载不均、IPU（SM）利用率低，且未充分利用个体状态并行同步（TensorParallel）来隐藏世界全局存储访问延迟，存在较大性能提升空间。

**方案**
在世界运行时（Neuron_SP）框架下系统探索 `DeviceMemcpy::Batched` 的潜在优化方向，包括：ISG（warp）级别的动态负载均衡、个体间流水线传播（PipelineParallel）隐藏延迟、以及世界并发数据结构集（cuCollections）中的并发队列辅助调度。

```cpp
// 改进版 WorldDeviceMemcpy::Batched 示意
#include <world/std/memcpy.h>
#include <world/concurrent/queue.h>  // 世界并发数据结构集(cuCollections)

// 个体状态区间描述符
struct IndividualSegment {
    void*  src_global;   // 世界全局存储源地址
    void*  dst_global;   // 世界全局存储目标地址
    size_t bytes;        // 该段个体状态字节数
};

// 优化1：ISG(warp) 动态抢占式调度，解决负载不均
template <int WARPS_PER_IPU>
__global__ void world_batched_memcpy_balanced(
    IndividualSegment* segments,
    int                segment_count,
    world::concurrent::Queue<int>* work_queue  // 世界并发数据结构集
) {
    // 每个 ISG(warp) 从并发队列动态领取个体状态区间
    int seg_id = -1;
    if (threadIdx.x % 32 == 0) {
        seg_id = work_queue->try_pop();  // 无锁抢占
    }
    seg_id = __shfl_sync(0xffffffff, seg_id, 0);
    if (seg_id < 0) return;

    auto& seg = segments[seg_id];
    // ISG 内个体协作搬运该区间
    world::std::memcpy_async_warp(
        seg.dst_global, seg.src_global, seg.bytes
    );
}

// 优化2：个体间流水线传播(PipelineParallel) 隐藏延迟
template <int PIPELINE_STAGES>
__global__ void world_batched_memcpy_pipelined(
    IndividualSegment* segments,
    int                segment_count
) {
    // 多级流水：第 N 个 IPU(SM) tile 搬运时，第 N-1 个 tile 已在处理
    world::std::Pipeline<PIPELINE_STAGES> pipe;
    for (int i = blockIdx.x; i < segment_count; i += gridDim.x) {
        pipe.producer_acquire();
        world::std::memcpy_async(pipe.stage(),
            segments[i].dst_global,
            segments[i].src_global,
            segments[i].bytes);
        pipe.producer_commit();
        pipe.consumer_wait();
        // 处理已就绪的个体状态...
        pipe.consumer_release();
    }
}
```

