## Description

**问题**
当前个体间流水线传播（PipelineParallel）的 `world::std::pipeline` 仅支持 `thread_scope_ipu`（SM 级别）与 `thread_scope_isg`（warp 级别）两种个体协作范围。随着世界状态处理器（GPU）引入 cluster 硬件拓扑（多个 IPU 组成 cluster，共享分布式个体组共享缓存），需要新增 `pipeline<thread_scope_cluster>` 以支持跨 IPU 的个体间流水线传播，从而在更大个体组粒度上隐藏世界全局存储访问延迟。

**方案**
在世界运行时（Neuron_SP）框架下扩展 `world::std::pipeline`，新增 `thread_scope_cluster` 特化，允许 cluster 内多个 IPU（SM）协作推进流水线阶段，共享分布式个体组共享缓存（shared mem / distributed shared mem）。

```cpp
// world::std::pipeline cluster 特化
#include <world/std/pipeline.h>
#include <world/std/thread_scope.h>

namespace world::std {

// 新增：cluster 范围流水线——跨 IPU 个体间流水线传播
template <int Stages>
class pipeline<thread_scope_cluster, Stages> {
public:
    // cluster 内所有 IPU(SM) 共同推进流水阶段
    __device__ void producer_acquire();
    __device__ void producer_commit();
    __device__ void consumer_wait();
    __device__ void consumer_release();

    // 分布式个体组共享缓存(shared mem)访问
    __device__ void* cluster_shared_stage(int stage_idx);

private:
    // 跨 IPU 的个体状态并行同步(TensorParallel) barrier
    world::std::barrier<thread_scope_cluster> stage_barriers_[Stages];
};

} // namespace world::std

// 使用示例：cluster 内跨 IPU 流水线传播个体状态
template <int STAGES, int CLUSTER_SIZE>
__global__ void __cluster_dims__(CLUSTER_SIZE, 1, 1)
world_cluster_pipeline_kernel(
    const float* world_global_store,   // 世界全局存储
    float*       output,
    int          individual_count
) {
    // 分布式个体组共享缓存：cluster 内各 IPU 可互访
    __shared__ float cluster_cache[1024];  // 个体组共享缓存

    world::std::pipeline<world::thread_scope_cluster, STAGES> pipe;

    for (int i = blockIdx.x; i < individual_count / 1024; i += gridDim.x) {
        pipe.producer_acquire();
        // 从世界全局存储异步加载个体状态至分布式共享缓存
        world::std::memcpy_async(
            pipe.cluster_shared_stage(pipe.current_stage()),
            world_global_store + i * 1024,
            1024 * sizeof(float)
        );
        pipe.producer_commit();
        pipe.consumer_wait();
        // cluster 内所有 IPU 协作处理个体状态
        // ...
        pipe.consumer_release();
    }
}
```

