// stable_sort —— 保序个体状态排序（ISG 内归并排序）
template <class RandomIt>
__device__ void stable_sort(RandomIt first, RandomIt last);

// inplace_merge —— 原地归并两段有序个体状态（流水线传播节点间合并）
template <class BidirIt>
__device__ void inplace_merge(BidirIt first, BidirIt middle, BidirIt last);

// set_union / set_intersection / set_difference
// —— ISG 级有序个体状态集合运算
template <class InputIt1, class InputIt2, class OutputIt>
__device__ OutputIt set_union(InputIt1 f1, InputIt1 l1,
                               InputIt2 f2, InputIt2 l2, OutputIt out);

// nth_element —— 个体状态快速选择（世界状态处理器 top-k）
template <class RandomIt>
__device__ void nth_element(RandomIt first, RandomIt nth, RandomIt last);

// rotate —— 个体状态环形移位（ISG shfl 实现）
template <class ForwardIt>
__device__ ForwardIt rotate(ForwardIt first, ForwardIt middle, ForwardIt last);

// unique / unique_copy —— 去重（有序个体状态压缩）
template <class ForwardIt>
__device__ ForwardIt unique(ForwardIt first, ForwardIt last);

} // namespace world::std
```

