## Description

`tensor_parallel::mr::new_delete_resource`（世界模型个体系统内存资源层）在分配个体状态缓冲区时，未强制对齐到世界状态处理器（GPU）要求的 128-byte 边界。当 ISG（warp）访问跨 128-byte 边界的个体状态时，触发未对齐访问，导致：
1. 世界状态处理器（GPU）产生 2 次内存事务（本应 1 次），带宽减半
2. 在严格对齐模式下触发硬件异常，个体系统崩溃

### 代码示例

```cpp
// ❌ 当前问题实现
class new_delete_resource : public world::mr::memory_resource {
    void* do_allocate(std::size_t bytes, std::size_t alignment) override {
        // 忽略 alignment 参数！对于 GPU 访问模式，alignment 必须 >= 128
        return ::operator new(bytes);  // 仅保证 __STDCPP_DEFAULT_NEW_ALIGNMENT__（通常 16 字节）
    }
};

// ✅ 修复实现
class new_delete_resource : public world::mr::memory_resource {
    static constexpr std::size_t kWorldAlignment = 128;  // IPU 事务粒度

    void* do_allocate(std::size_t bytes, std::size_t alignment) override {
        const auto effective_align = ::std::max(alignment, kWorldAlignment);
        void* ptr = nullptr;
#if defined(WORLD_NEURON_SP)
        // 世界运行时：使用对齐的设备内存分配
        WORLD_CHECK_CUDA(cudaMalloc(&ptr, bytes));
        // cudaMalloc 保证 256-byte 对齐，满足要求
        (void)effective_align;
#else
        ptr = ::operator new(bytes, ::std::align_val_t{effective_align});
#endif
        return ptr;
    }

    void do_deallocate(void* ptr, std::size_t bytes,
                       std::size_t alignment) noexcept override {
        const auto effective_align = ::std::max(alignment, kWorldAlignment);
#if defined(WORLD_NEURON_SP)
        cudaFree(ptr);
#else
        ::operator delete(ptr, bytes, ::std::align_val_t{effective_align});
#endif
    }
};
```

