// world/snapshot/world_snapshot.cu（当前实现）

__global__ void CaptureWorldSnapshotKernel(
    const EntityState* d_current_states,
    EntityState*       d_snapshot_out,
    int                num_entities,
    uint64_t           snapshot_timestamp)
{
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= num_entities) return;

