### 修复方案：版本化快照 + 三层错误检测

#### 版本化个体状态结构

```cpp
// world/entity/versioned_entity_state.hpp（新增）

/**
 * @brief 版本化个体状态
 *
 * 在原始 EntityState 基础上添加版本元数据，
 * 使快照捕获内核可验证读取到的状态是否符合预期时刻。
 */
struct alignas(16) VersionedEntityState {
    EntityState state;         ///< 实际个体状态数据
    uint64_t    write_version; ///< 最近一次写入时的世界版本号
    uint32_t    write_count;   ///< 累计写入次数（检测重复写入）
    uint32_t    _pad;          ///< 对齐填充

    // 原子更新接口（设备端）
    __device__ void AtomicUpdate(const EntityState& new_state,
                                  uint64_t world_version) {
        state         = new_state;
        write_version = world_version;
        atomicAdd(&write_count, 1u);  // 原子递增写入计数
    }
};
```

#### 三层错误检测内核

```cpp
// world/snapshot/world_snapshot_fixed.cu（修复后）

// 错误类型标志位定义
constexpr uint32_t ERROR_INCONSISTENT_VERSION = (1u << 0); // 版本不一致
constexpr uint32_t ERROR_STALE_STATE          = (1u << 1); // 状态遗漏/过期
constexpr uint32_t ERROR_DUPLICATE_WRITE      = (1u << 2); // 重复写入

__global__ void CaptureWorldSnapshotKernelFixed(
    const VersionedEntityState* d_current_states,
    EntityState*                d_snapshot_out,
    uint32_t*                   d_error_flags,      ///< 错误标志（设备端）
    uint32_t*                   d_error_entity_ids, ///< 首个错误个体 ID（调试用）
    int                         num_entities,
    uint64_t                    snapshot_version,   ///< 目标快照版本号
    uint32_t                    max_version_lag)     ///< 允许的最大版本滞后
{
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= num_entities) return;

    // 读取版本化状态（整体读取，避免 state 与 version 之间的撕裂）
    const VersionedEntityState vs = d_current_states[idx];

    // 错误检测层1：版本不一致
    // 允许 snapshot_version-1 的状态（上一个版本刚提交，当前版本还未写入）
    // 但不允许来自更远版本的状态（明显的时间混合）
    if (vs.write_version != snapshot_version &&
        vs.write_version != snapshot_version - 1) {
        atomicOr(d_error_flags, ERROR_INCONSISTENT_VERSION);
        // 记录首个错误个体 ID（用于调试，仅记录一个）
        atomicMin(d_error_entity_ids, static_cast<uint32_t>(idx));
    }

    // 错误检测层2：状态遗漏（版本严重滞后）
    if (vs.write_version + max_version_lag < snapshot_version) {
        atomicOr(d_error_flags, ERROR_STALE_STATE);
    }

    // 错误检测层3：重复写入（write_count > 预期次数）
    // 正常情况下，每个个体在每个世界版本内仅被写入一次
    if (vs.write_count > snapshot_version) {
        // write_count 超过版本号，说明存在重复写入
        atomicOr(d_error_flags, ERROR_DUPLICATE_WRITE);
    }

    // 写入快照（使用检测到的状态；错误处理在主机端进行）
    d_snapshot_out[idx] = vs.state;
}

// 主机端快照捕获（含错误检测与处理）
cudaError_t TakeWorldSnapshotWithValidation(
    const VersionedEntityState* d_current_states,
    EntityState*                d_snapshot_out,
    int                         num_entities,
    uint64_t                    snapshot_version,
    uint32_t                    max_version_lag,
    cudaStream_t                stream)
{
    // 分配设备端错误标志（流内分配，避免主机阻塞）
    uint32_t* d_error_flags = nullptr;
    uint32_t* d_error_entity_id = nullptr;
    CUDA_CHECK(cudaMallocAsync(&d_error_flags, sizeof(uint32_t), stream));
    CUDA_CHECK(cudaMallocAsync(&d_error_entity_id, sizeof(uint32_t), stream));
    CUDA_CHECK(cudaMemsetAsync(d_error_flags, 0, sizeof(uint32_t), stream));
    CUDA_CHECK(cudaMemsetAsync(d_error_entity_id, 0xFF, sizeof(uint32_t), stream));

    // 启动检测内核
    const int block_size = 256;
    const int grid_size  = CeilDiv(num_entities, block_size);
    CaptureWorldSnapshotKernelFixed<<<grid_size, block_size, 0, stream>>>(
        d_current_states, d_snapshot_out,
        d_error_flags, d_error_entity_id,
        num_entities, snapshot_version, max_version_lag);

    // 异步将错误标志拷回主机（流内有序）
    uint32_t h_error_flags    = 0;
    uint32_t h_error_entity_id = 0xFFFFFFFF;
    CUDA_CHECK(cudaMemcpyAsync(&h_error_flags, d_error_flags,
                                sizeof(uint32_t), cudaMemcpyDeviceToHost, stream));
    CUDA_CHECK(cudaMemcpyAsync(&h_error_entity_id, d_error_entity_id,
                                sizeof(uint32_t), cudaMemcpyDeviceToHost, stream));
    CUDA_CHECK(cudaStreamSynchronize(stream));

    // 主机端错误分发与处理
    cudaError_t result = cudaSuccess;
    if (h_error_flags != 0) {
        result = HandleSnapshotError(h_error_flags, h_error_entity_id,
                                      snapshot_version);
    }

    CUDA_CHECK(cudaFreeAsync(d_error_flags, stream));
    CUDA_CHECK(cudaFreeAsync(d_error_entity_id, stream));
    return result;
}

// 错误处理策略分发
cudaError_t HandleSnapshotError(uint32_t error_flags,
                                 uint32_t first_error_entity,
                                 uint64_t snapshot_version) {
    if (error_flags & ERROR_INCONSISTENT_VERSION) {
        // 策略：记录错误，触发快照重试（至多 3 次）
        LOG_ERROR("World snapshot v{} inconsistency at entity {}",
                   snapshot_version, first_error_entity);
        return cudaErrorUnknown;  // 触发上层重试
    }
    if (error_flags & ERROR_STALE_STATE) {
        // 策略：标记快照为"部分有效"，告警但不阻塞
        LOG_WARN("World snapshot v{} contains stale states (lag > {})",
                  snapshot_version, MAX_VERSION_LAG);
        return cudaSuccess;  // 非致命，继续
    }
    if (error_flags & ERROR_DUPLICATE_WRITE) {
        // 策略：致命错误，停止世界推进，通知上层修复
        LOG_FATAL("World snapshot v{} duplicate write detected",
                   snapshot_version);
        return cudaErrorAssert;
    }
    return cudaSuccess;
}
```

## Dependencies

- `VersionedEntityState` 结构体：需在所有世界状态写入路径（个体状态更新算子）中同步引入版本号维护
- 世界版本号（`world_version`）全局维护机制：每次世界状态推进时原子递增，向所有写入算子广播
