## 世界模型个体系统 PRD — 在 DistributedCore 和 libnv++ 中支持 `<random>`

### 背景与动机

在 Neuron_SP（世界运行时）中，个体状态的随机初始化和世界状态的随机扰动（用于感知噪声模拟、探索策略等）是核心需求。C++ 标准库 `<random>` 提供了丰富的随机数引擎（`mt19937`、`xoshiro256**` 等）和分布（`uniform_int_distribution`、`normal_distribution` 等），但当前 DistributedCore（跨世界状态处理器分布式运行时）和 libnv++（world::std 的底层实现库）均不支持在世界状态处理器（GPU）设备代码中使用 `<random>`。

缺失的能力：

```cpp
// 在 ISG（warp）内生成随机世界状态扰动
__device__ void perturb_world_state(world::individual_state& state) {
    // 当前：需手写 LCG 或使用 cuRAND（重量级依赖）
    // 期望：直接使用 world::std::mt19937 等标准引擎
    world::std::mt19937 rng(world::individual_id());
    world::std::normal_distribution<float> dist(0.0f, 0.01f);
    state.position += dist(rng);  // 目前编译失败
}
```

### 问题陈述

1. `<random>` 的标准引擎（如 `mt19937`）使用大量 host-only 特性（异常、虚函数、堆分配），无法直接在设备代码中使用。
2. `libnv++` 缺少对 `<random>` 头文件的设备代码适配层。
3. DistributedCore 的个体状态初始化路径无法使用标准随机分布，导致各世界状态处理器上的个体状态分布不一致。
4. 个体间流水线传播（PipelineParallel）的随机种子管理缺乏统一 API。

### 目标

1. 在 `world::std`（映射自 `neuron::std`）中提供完整的 `<random>` 设备侧适配。
2. 支持至少：`world::std::mt19937`、`world::std::xoshiro256ss`、`world::std::uniform_int_distribution`、`world::std::uniform_real_distribution`、`world::std::normal_distribution`。
3. 在 DistributedCore 中提供跨世界状态处理器确定性随机种子分配 API。
4. 与 `thread_scope_isg` 和 `thread_scope_system` 的个体状态并行同步（TensorParallel）兼容。

### 技术方案

#### world::std `<random>` 适配层架构

```
world/std/random
├── engines/
│   ├── mt19937.hpp          # 梅森旋转，状态 624×32 bit
│   ├── xoshiro256ss.hpp     # 高速 xoshiro256**，状态 4×64 bit
│   └── philox4x32.hpp       # 计数器基 PRNG，适合并行 ISG
├── distributions/
│   ├── uniform_int.hpp
│   ├── uniform_real.hpp
│   ├── normal.hpp           # Box-Muller 变换，无 std::log 依赖
│   └── bernoulli.hpp
└── seed_seq.hpp             # 跨世界状态处理器确定性种子序列
```

#### 核心引擎实现

```cpp
namespace world::std {

// xoshiro256**：轻量、高质量，适合 ISG 级并行随机数生成
struct xoshiro256ss {
    using result_type = uint64_t;
    static constexpr result_type min() { return 0; }
    static constexpr result_type max() { return UINT64_MAX; }

    __host__ __device__ explicit xoshiro256ss(uint64_t seed = 0) noexcept {
        // splitmix64 初始化，确保非零状态
        auto sm = [](uint64_t& x) -> uint64_t {
            x += 0x9e3779b97f4a7c15ULL;
            uint64_t z = x;
            z = (z ^ (z >> 30)) * 0xbf58476d1ce4e5b9ULL;
            z = (z ^ (z >> 27)) * 0x94d049bb133111ebULL;
            return z ^ (z >> 31);
        };
        s[0] = sm(seed); s[1] = sm(seed);
        s[2] = sm(seed); s[3] = sm(seed);
    }

    __host__ __device__ result_type operator()() noexcept {
        const uint64_t result = rotl(s[1] * 5, 7) * 9;
        const uint64_t t = s[1] << 17;
        s[2] ^= s[0]; s[3] ^= s[1];
        s[1] ^= s[2]; s[0] ^= s[3];
        s[2] ^= t;
        s[3] = rotl(s[3], 45);
        return result;
    }

    // jump()：将状态前进 2^128 步，用于 ISG 间无重叠并行流
    __host__ __device__ void jump() noexcept {
        static constexpr uint64_t JUMP[] = {
            0x180ec6d33cfd0abaULL, 0xd5a61266f0c9392cULL,
            0xa9582618e03fc9aaULL, 0x39abdc4529b1661cULL
        };
        uint64_t s0=0, s1=0, s2=0, s3=0;
        for (auto j : JUMP)
            for (int b = 0; b < 64; ++b) {
                if (j & (1ULL << b)) {
                    s0^=s[0]; s1^=s[1]; s2^=s[2]; s3^=s[3];
                }
                (*this)();
            }
        s[0]=s0; s[1]=s1; s[2]=s2; s[3]=s3;
    }

private:
    uint64_t s[4];
    static __host__ __device__ uint64_t rotl(uint64_t x, int k) noexcept {
        return (x << k) | (x >> (64 - k));
    }
};

// normal_distribution：Box-Muller，避免 host-only std::log/std::sqrt
template <typename RealType = float>
class normal_distribution {
public:
    __host__ __device__ explicit normal_distribution(
        RealType mean = 0, RealType stddev = 1) noexcept
        : mean_(mean), stddev_(stddev) {}

    template <typename URNG>
    __host__ __device__ RealType operator()(URNG& g) noexcept {
        // Box-Muller 变换（使用 world::std::log / world::std::sqrt）
        RealType u1 = (g() + RealType(0.5)) / (RealType(URNG::max()) + 1);
        RealType u2 = (g() + RealType(0.5)) / (RealType(URNG::max()) + 1);
        RealType z  = world::std::sqrt(-2 * world::std::log(u1))
                    * world::std::cos(2 * M_PIf * u2);
        return mean_ + stddev_ * z;
    }
private:
    RealType mean_, stddev_;
};

} // namespace world::std
```

#### DistributedCore 种子分配 API

```cpp
namespace world::distributed {

/// 为每个世界状态处理器（GPU）的每个 ISG 生成确定性、无重叠的随机种子序列。
/// 保证：不同世界状态处理器 / ISG 的随机流互不重叠，复现性由全局 seed 控制。
///
/// @param global_seed  全局随机种子（由 world::master 分配）
/// @param gpu_rank     当前世界状态处理器编号（0 ~ num_gpus-1）
/// @param isg_id       当前 ISG 编号（0 ~ num_isgs-1）
__device__ world::std::xoshiro256ss
make_individual_rng(uint64_t global_seed, int gpu_rank, int isg_id) {
    // 将全局种子与设备/ISG 编号混合，生成唯一本地种子
    uint64_t local_seed = global_seed
        ^ (static_cast<uint64_t>(gpu_rank) << 32)
        ^ static_cast<uint64_t>(isg_id);
    world::std::xoshiro256ss rng(local_seed);
    // jump() 确保不同 ISG 的随机流间隔 2^128 步
    for (int i = 0; i < isg_id; ++i) rng.jump();
    return rng;
}

} // namespace world::distributed
```

#### 完整使用示例

```cpp
// 在 Neuron_SP kernel 中初始化带随机扰动的个体状态
__global__ void init_individual_states(
    world::individual_state* states,
    uint64_t global_seed,
    int gpu_rank)
{
    int isg_id = blockIdx.x;
    // 每个 ISG 获得独立的随机流
    auto rng = world::distributed::make_individual_rng(
        global_seed, gpu_rank, isg_id);

    world::std::normal_distribution<float> pos_dist(0.0f, 1.0f);
    world::std::uniform_real_distribution<float> vel_dist(-0.1f, 0.1f);

    // ISG 内各线程处理不同个体
    int tid = threadIdx.x;
    states[isg_id * blockDim.x + tid].position = pos_dist(rng);
    states[isg_id * blockDim.x + tid].velocity = vel_dist(rng);
}
```

