## 世界模型个体系统 PRD — 改进错误处理工具链

### 背景与动机

Neuron_SP（世界运行时）在个体间流水线传播（PipelineParallel）和个体状态并行同步（TensorParallel）过程中会产生多种运行时错误：同步超时、世界状态处理器（GPU）内存越界、ISG（warp）发散异常等。当前错误处理工具链存在以下严重缺陷：

1. **错误信息不透明**：设备侧错误仅返回整型错误码，无上下文（调用栈、ISG ID、世界时钟戳）。
2. **跨层传播困难**：从 IPU（SM）内部发生的错误无法可靠传播到 Host 侧的世界调度器。
3. **缺乏结构化错误类型**：`neuron::error_code`（映射为 `world::error_code`）是扁平枚举，无法表达嵌套错误原因链。
4. **调试体验差**：在 Compute Sanitizer 外无法获取错误发生时的 ISG 状态快照。

### 问题陈述

```cpp
// 当前错误处理（典型模式）
__device__ int world_compute(world::individual_state* state) {
    if (state == nullptr) return -1;          // 错误码不透明
    auto result = sync_barrier_.arrive();
    if (!result.valid()) return -2;            // 无法知道为什么失败
    // ... 计算 ...
    return 0;
}

// Host 侧
auto err = cudaGetLastError();
if (err != cudaSuccess) {
    // 只有 "invalid device function" 这类粗糙信息
    fprintf(stderr, "Error: %s\n", cudaGetErrorString(err));
    // 无法知道哪个 ISG、哪个个体状态、什么时间点
}
```

### 目标

1. 引入结构化 `world::error` 类型，携带错误码、消息、上下文（ISG ID、世界时钟戳、调用位置）。
2. 实现设备→Host 错误传播通道（利用 pinned memory 环形缓冲区）。
3. 提供 `world::expected<T, world::error>` 作为无异常的错误返回惯用法。
4. 在 Neuron_SP 调度器中集成错误聚合与报告 API。
5. 与现有 Compute Sanitizer 集成，在 sanitizer 模式下自动附加更多诊断信息。

### 技术方案

#### 结构化错误类型

```cpp
namespace world {

enum class error_code : uint32_t {
    success             = 0,
    barrier_timeout     = 1,   // world::barrier 等待超时
    memory_fault        = 2,   // 世界状态内存越界访问
    isg_divergence      = 3,   // ISG 内部控制流发散
    pipeline_stall      = 4,   // 个体间流水线传播停滞
    state_corruption    = 5,   // 个体状态校验失败
    rng_exhausted       = 6,   // 随机数流耗尽（world::std::random）
    unknown             = 0xFF
};

struct error_location {
    const char* file;
    int         line;
    const char* function;
};

struct error_context {
    int      isg_id;       // ISG（warp）编号
    int      gpu_rank;     // 世界状态处理器编号
    uint64_t world_clock;  // Neuron_SP 世界时钟戳
};

class error {
public:
    __host__ __device__ error(
        error_code code,
        const char* message,
        error_location loc,
        error_context ctx) noexcept
        : code_(code), message_(message), loc_(loc), ctx_(ctx) {}

    __host__ __device__ error_code     code()    const noexcept { return code_; }
    __host__ __device__ const char*    message() const noexcept { return message_; }
    __host__ __device__ error_location location()const noexcept { return loc_; }
    __host__ __device__ error_context  context() const noexcept { return ctx_; }

    // 错误原因链（最多 4 层）
    __host__ __device__ const error*   cause()   const noexcept { return cause_; }
    __host__ __device__ error&         with_cause(const error& e) noexcept {
        cause_ = &e; return *this;
    }

private:
    error_code     code_;
    const char*    message_;
    error_location loc_;
    error_context  ctx_;
    const error*   cause_ = nullptr;
};

// 便利宏：自动填充 error_location
#define WORLD_MAKE_ERROR(code, msg) \
    world::error(code, msg, \
        world::error_location{__FILE__, __LINE__, __FUNCTION__}, \
        world::error_context{world::this_isg_id(), \
                             world::this_gpu_rank(), \
                             world::world_clock()})

} // namespace world
```

#### world::expected<T, E>

```cpp
namespace world {

template <typename T, typename E = world::error>
class expected {
public:
    __host__ __device__ expected(T val)    : has_val_(true),  val_(val)  {}
    __host__ __device__ expected(E err)    : has_val_(false), err_(err)  {}

    __host__ __device__ bool     has_value() const noexcept { return has_val_; }
    __host__ __device__ T&       value()           noexcept { return val_; }
    __host__ __device__ const E& error()      const noexcept { return err_; }

    // 单子式操作
    template <typename F>
    __host__ __device__ auto and_then(F&& f) noexcept
        -> expected<decltype(f(val_)), E>
    {
        if (has_val_) return f(val_);
        return err_;
    }

private:
    bool has_val_;
    union { T val_; E err_; };
};

} // namespace world
```

#### 设备→Host 错误传播通道

```cpp
namespace world::error_channel {

// Pinned memory 环形缓冲区（Host 分配，Device 写入）
struct alignas(64) error_slot {
    world::error err;
    cuda::atomic<uint32_t, cuda::thread_scope_system> ready;
};

constexpr int CHANNEL_CAPACITY = 256;

struct error_channel_t {
    error_slot slots[CHANNEL_CAPACITY];
    cuda::atomic<uint32_t, cuda::thread_scope_system> write_head;
    cuda::atomic<uint32_t, cuda::thread_scope_system> read_head;
};

// 设备侧：发布错误（非阻塞）
__device__ void publish(error_channel_t* ch, const world::error& err) {
    uint32_t idx = ch->write_head.fetch_add(1, cuda::memory_order_relaxed,
                                             cuda::thread_scope_system)
                   % CHANNEL_CAPACITY;
    ch->slots[idx].err = err;
    ch->slots[idx].ready.store(1, cuda::memory_order_release,
                                cuda::thread_scope_system);
}

// Host 侧：轮询消费错误
bool poll(error_channel_t* ch, world::error& out) {
    uint32_t r = ch->read_head.load(std::memory_order_relaxed);
    uint32_t w = ch->write_head.load(std::memory_order_acquire);
    if (r == w) return false;
    auto& slot = ch->slots[r % CHANNEL_CAPACITY];
    if (!slot.ready.load(std::memory_order_acquire)) return false;
    out = slot.err;
    slot.ready.store(0, std::memory_order_release);
    ch->read_head.fetch_add(1, std::memory_order_release);
    return true;
}

} // namespace world::error_channel
```

#### 集成示例：个体状态同步错误处理

```cpp
// 使用新工具链的 barrier 同步
__device__ world::expected<void, world::error>
safe_arrive_and_wait(world::barrier<world::thread_scope_isg>& bar,
                     world::error_channel::error_channel_t* ch)
{
    auto token = bar.arrive();
    constexpr int MAX_RETRIES = 1000;
    int retries = 0;
    while (!bar.try_wait(world::copy(token))) {
        if (++retries > MAX_RETRIES) {
            auto err = WORLD_MAKE_ERROR(
                world::error_code::barrier_timeout,
                "world::barrier::try_wait exceeded max retries during "
                "individual state parallel sync (TensorParallel)");
            world::error_channel::publish(ch, err);
            return err;
        }
        __nanosleep(4u << min(retries, 8));  // 指数退避
    }
    return {};  // success
}
```

