## 世界模型个体系统 PRD — 审查 `<bit>` 实现中的 hack 并优化

### 背景与动机

world::std `<bit>`（映射自 `neuron::std <bit>`）为 Neuron_SP（世界运行时）提供位操作原语，包括 `world::std::popcount`、`world::std::countl_zero`、`world::std::countr_zero`、`world::std::bit_width`、`world::std::has_single_bit` 等。这些函数在 ISG（warp）级别的个体状态并行同步（TensorParallel）掩码操作、世界状态处理器（GPU）内存对齐计算中被高频调用。

历史原因：早期 world::std `<bit>` 实现为了绕过 NVCC / 旧编译器的限制，引入了若干"hack"：

1. **软件 popcount 替代硬件指令**：在应使用 `__popc()` PTX 内置函数的地方，使用 Brian Kernighan 算法（循环实现），每次调用比硬件指令慢 4–8 倍。
2. **手写 CLZ 替代 `__clz()`**：使用二分查找实现前导零计数，而非单条 PTX `bfind` 指令。
3. **位反转（`bit_ceil` 路径）中的未定义行为**：对于 `x = 0` 的边界情况，当前实现返回 0 而非标准要求的 1，且无断言保护。
4. **`__builtin_expect` 和 `[[likely]]` 标注缺失**：ISG 内的快速路径（2 的幂次判断）未标注分支预测提示。
5. **常量折叠障碍**：部分 `constexpr` 路径因包含 `reinterpret_cast` 而无法在编译期计算。

### 问题陈述

```cpp
// 当前：软件 popcount（慢）
__device__ int world::std::popcount(uint32_t x) noexcept {
    // Brian Kernighan 算法 — 最坏情况 32 次循环
    int count = 0;
    while (x) { x &= x - 1; ++count; }
    return count;
    // PTX 输出：loop.do / setp / br — 约 32 条指令
}

// 期望：硬件 popc 指令
__device__ int world::std::popcount(uint32_t x) noexcept {
    return __popc(x);  // 单条 PTX: popc.b32 %r0, %r1;
}

// 当前：bit_ceil 边界未定义行为
__device__ uint32_t world::std::bit_ceil(uint32_t x) noexcept {
    if (x <= 1) return 0;  // 错误！标准要求返回 1
    // ...
}
```

### 目标

1. 全面审查 `<world/std/bit>` 实现，记录所有 hack 的来源和当前必要性。
2. 将可替换的软件实现换为对应的 PTX 内置函数（`__popc`、`__clz`、`__brev` 等）。
3. 修复所有已知的 C++ 标准不符合项（边界条件、未定义行为）。
4. 添加 `constexpr` 路径，使编译期常量输入在世界状态处理器 `__constant__` 内存初始化中正确折叠。
5. 添加分支预测标注（`[[likely]]`/`[[unlikely]]`），优化 ISG 内快速路径。

### 技术方案

#### 完整优化后的 `<world/std/bit>` 实现

```cpp
// world/std/bit — 优化版本
#pragma once
#include <world/detail/compiler_check.hpp>
#include <type_traits>

namespace world::std {

// ── popcount ──────────────────────────────────────────────────
template <typename T>
[[nodiscard]] __host__ __device__
constexpr int popcount(T x) noexcept {
    static_assert(::std::is_unsigned_v<T>, "popcount requires unsigned type");
#ifdef __CUDA_ARCH__
    // 设备代码：使用 PTX 硬件指令
    if constexpr (sizeof(T) <= 4)
        return __popc(static_cast<unsigned int>(x));
    else
        return __popcll(static_cast<unsigned long long>(x));
#else
    // 宿主代码：使用编译器内置（GCC/Clang/MSVC 均有）
    if constexpr (sizeof(T) <= 4)
        return __builtin_popcount(static_cast<unsigned int>(x));
    else
        return __builtin_popcountll(static_cast<unsigned long long>(x));
#endif
}

// ── countl_zero（前导零计数）──────────────────────────────────
template <typename T>
[[nodiscard]] __host__ __device__
constexpr int countl_zero(T x) noexcept {
    static_assert(::std::is_unsigned_v<T>);
    if (x == 0) [[unlikely]] return sizeof(T) * 8;
#ifdef __CUDA_ARCH__
    if constexpr (sizeof(T) <= 4) {
        // __clz 对 32 位值返回前导零数（PTX: bfind.shiftamt）
        int clz = __clz(static_cast<unsigned int>(x));
        // 修正：__clz 总对 32 位计算，需补偿小类型的高位
        return clz - (32 - static_cast<int>(sizeof(T) * 8));
    } else {
        return __clzll(static_cast<unsigned long long>(x));
    }
#else
    if constexpr (sizeof(T) <= 4)
        return __builtin_clz(static_cast<unsigned int>(x))
               - (32 - static_cast<int>(sizeof(T) * 8));
    else
        return __builtin_clzll(static_cast<unsigned long long>(x));
#endif
}

// ── countr_zero（尾部零计数）──────────────────────────────────
template <typename T>
[[nodiscard]] __host__ __device__
constexpr int countr_zero(T x) noexcept {
    static_assert(::std::is_unsigned_v<T>);
    if (x == 0) [[unlikely]] return sizeof(T) * 8;
#ifdef __CUDA_ARCH__
    if constexpr (sizeof(T) <= 4)
        return __ffs(static_cast<int>(x)) - 1;  // PTX: bfind
    else
        return __ffsll(static_cast<long long>(x)) - 1;
#else
    if constexpr (sizeof(T) <= 4)
        return __builtin_ctz(static_cast<unsigned int>(x));
    else
        return __builtin_ctzll(static_cast<unsigned long long>(x));
#endif
}

// ── has_single_bit（2 的幂次判断）────────────────────────────
template <typename T>
[[nodiscard]] __host__ __device__
constexpr bool has_single_bit(T x) noexcept {
    static_assert(::std::is_unsigned_v<T>);
    return x != 0 && (x & (x - 1)) == 0;  // 经典位技巧，无 hack
}

// ── bit_ceil（向上取整到 2 的幂）──────────────────────────────
// 修复：x == 0 或 x == 1 时返回 1（标准行为）
template <typename T>
[[nodiscard]] __host__ __device__
constexpr T bit_ceil(T x) noexcept {
    static_assert(::std::is_unsigned_v<T>);
    if (x <= 1) [[unlikely]] return T(1);  // 修复：原来返回 0（UB）
    return T(1) << (sizeof(T) * 8 - countl_zero(T(x - 1)));
}

// ── bit_floor（向下取整到 2 的幂）────────────────────────────
template <typename T>
[[nodiscard]] __host__ __device__
constexpr T bit_floor(T x) noexcept {
    static_assert(::std::is_unsigned_v<T>);
    if (x == 0) [[unlikely]] return T(0);
    return T(1) << (sizeof(T) * 8 - 1 - countl_zero(x));
}

// ── byteswap（字节序反转）─────────────────────────────────────
template <typename T>
[[nodiscard]] __host__ __device__
constexpr T byteswap(T x) noexcept {
    static_assert(::std::is_unsigned_v<T>);
#ifdef __CUDA_ARCH__
    if constexpr (sizeof(T) == 4) return __byte_perm(x, 0, 0x0123);
    if constexpr (sizeof(T) == 2) return ((x >> 8) | (x << 8));
    if constexpr (sizeof(T) == 8) {
        uint32_t lo = __byte_perm(static_cast<uint32_t>(x),       0, 0x0123);
        uint32_t hi = __byte_perm(static_cast<uint32_t>(x >> 32), 0, 0x0123);
        return (static_cast<uint64_t>(lo) << 32) | hi;
    }
#else
    if constexpr (sizeof(T) == 2) return __builtin_bswap16(x);
    if constexpr (sizeof(T) == 4) return __builtin_bswap32(x);
    if constexpr (sizeof(T) == 8) return __builtin_bswap64(x);
#endif
    return x;  // sizeof(T) == 1
}

// ── rotl / rotr（循环移位）────────────────────────────────────
template <typename T>
[[nodiscard]] __host__ __device__
constexpr T rotl(T x, int s) noexcept {
    static_assert(::std::is_unsigned_v<T>);
    constexpr int N = sizeof(T) * 8;
    s &= (N - 1);
    if (s == 0) [[unlikely]] return x;
    return (x << s) | (x >> (N - s));
}

template <typename T>
[[nodiscard]] __host__ __device__
constexpr T rotr(T x, int s) noexcept {
    return rotl(x, -s);
}

} // namespace world::std
```

