## 世界模型个体系统 PRD — `world::annotated_ptr` 头文件无法在宿主代码中引入

### 背景与动机

`world::annotated_ptr`（映射自 `neuron::annotated_ptr`）是 Neuron_SP（世界运行时）中的智能指针类型，用于携带访问属性标注（内存空间类型、对齐保证、只读/读写权限），供世界状态处理器（GPU）的 IPU（SM）生成更优化的 PTX 内存访问指令。

**当前问题**：`<world/annotated_ptr>` 头文件包含设备代码特有的关键字和属性（`__device__`、`__restrict__`、`__ldg()`、`__builtin_assume_aligned()`），导致在纯宿主（CPU）代码中 `#include <world/annotated_ptr>` 时编译失败：

```
$ g++ -std=c++17 host_manager.cpp
host_manager.cpp:3:10: error: #include <world/annotated_ptr>
In file included from world/annotated_ptr:8:
world/detail/annotated_ptr_impl.hpp:47:5: error:
  '__device__' does not name a type
world/detail/annotated_ptr_impl.hpp:112:18: error:
  '__ldg' was not declared in this scope
```

这阻碍了以下合法的宿主代码使用场景：
1. 宿主侧世界调度器需要持有 `world::annotated_ptr<individual_state>` 类型的指针容器（STL vector）。
2. IPC 屏障工厂 API 的参数类型使用了 `world::annotated_ptr`（见 PRD #3）。
3. 单元测试框架（运行在 CPU 上）无法测试包含 `world::annotated_ptr` 参数的世界状态 API。

### 问题陈述

```cpp
// 宿主代码：world_scheduler.hpp
#include <world/annotated_ptr>  // 编译失败：__device__ 符号不可用

class WorldScheduler {
    // 宿主侧持有设备指针的 annotated_ptr
    std::vector<world::annotated_ptr<world::individual_state>> state_ptrs_;
    // 需要知道指针的访问属性（对齐、只读性）用于 cudaMemcpy 策略决策
};

// 期望：上述代码在纯 g++ 编译下通过，world::annotated_ptr 退化为
// 持有原始指针 + 属性元数据的轻量包装，无设备特有行为。
```

### 目标

1. 重构 `<world/annotated_ptr>`，使其可在宿主代码中无错误引入。
2. 宿主侧 `world::annotated_ptr<T>` 退化为持有 `T*` 指针和属性标注枚举的轻量结构，无 PTX 生成相关代码。
3. 设备侧行为不变：仍生成 `__ldg`、`ld.global.nc` 等优化 PTX 访问指令。
4. 宿主侧和设备侧共享相同的属性枚举定义，确保类型互操作性。
5. 解决头文件中所有 `__device__`、`__host__`、`__restrict__` 的条件编译问题。

### 技术方案

#### 分层头文件架构

```
world/
  annotated_ptr              ← 用户入口（宿主+设备均可引入）
  detail/
    annotated_ptr_attrs.hpp  ← 属性枚举（纯 C++，宿主+设备共用）
    annotated_ptr_host.hpp   ← 宿主侧实现（无设备关键字）
    annotated_ptr_device.hpp ← 设备侧实现（含 PTX 优化路径）
```

#### 属性枚举（公共层，无设备关键字）

```cpp
// world/detail/annotated_ptr_attrs.hpp
#pragma once
#include <cstddef>
#include <cstdint>

namespace world {

enum class ptr_access : uint8_t {
    read_write  = 0,
    read_only   = 1,   // 设备侧映射到 ld.global.nc（非一致性缓存）
    write_only  = 2,
};

enum class ptr_space : uint8_t {
    global      = 0,   // 世界状态处理器全局内存
    shared      = 1,   // IPU 共享内存
    constant    = 2,   // __constant__ 内存
    local       = 3,   // ISG 私有本地内存
    generic     = 4,   // 泛型地址空间（默认）
};

struct ptr_annotations {
    ptr_access access    = ptr_access::read_write;
    ptr_space  space     = ptr_space::global;
    uint32_t   alignment = alignof(::std::max_align_t);  // 字节对齐
    bool       restrict_ = false;  // 无别名保证
};

} // namespace world
```

#### 宿主侧实现（无设备关键字）

```cpp
// world/detail/annotated_ptr_host.hpp
#pragma once
#include <world/detail/annotated_ptr_attrs.hpp>
#include <type_traits>
#include <cassert>

namespace world {

template <typename T>
class annotated_ptr {
public:
    using element_type = T;
    using pointer      = T*;

    // 宿主侧构造
    constexpr annotated_ptr() noexcept = default;
    constexpr explicit annotated_ptr(T* ptr,
        ptr_annotations ann = {}) noexcept
        : ptr_(ptr), ann_(ann) {}

    // 宿主侧解引用（普通指针语义）
    T& operator*()  const noexcept { return *ptr_; }
    T* operator->() const noexcept { return ptr_; }
    T* get()        const noexcept { return ptr_; }

    // 属性访问（宿主侧用于 cudaMemcpy 策略决策）
    ptr_access     access()    const noexcept { return ann_.access; }
    ptr_space      space()     const noexcept { return ann_.space; }
    uint32_t       alignment() const noexcept { return ann_.alignment; }
    bool           is_restrict() const noexcept { return ann_.restrict_; }
    ptr_annotations annotations() const noexcept { return ann_; }

    // 指针算术
    annotated_ptr operator+(ptrdiff_t n) const noexcept {
        return annotated_ptr(ptr_ + n, ann_);
    }
    annotated_ptr& operator+=(ptrdiff_t n) noexcept {
        ptr_ += n; return *this;
    }

    explicit operator bool() const noexcept { return ptr_ != nullptr; }
    explicit operator T*()   const noexcept { return ptr_; }

    // 比较
    bool operator==(const annotated_ptr& rhs) const noexcept {
        return ptr_ == rhs.ptr_;
    }
    bool operator!=(const annotated_ptr& rhs) const noexcept {
        return !(*this == rhs);
    }

private:
    T*              ptr_ = nullptr;
    ptr_annotations ann_{};
};

} // namespace world
```

#### 设备侧实现（含 PTX 优化）

```cpp
// world/detail/annotated_ptr_device.hpp
#pragma once
#include <world/detail/annotated_ptr_attrs.hpp>

namespace world {

template <typename T>
class annotated_ptr {
public:
    using element_type = T;
    using pointer      = T*;

    __host__ __device__ constexpr annotated_ptr() noexcept = default;
    __host__ __device__ constexpr explicit annotated_ptr(
        T* ptr, ptr_annotations ann = {}) noexcept
        : ptr_(ptr), ann_(ann) {}

    // 设备侧解引用：根据属性选择最优 PTX 加载指令
    __device__ T& operator*() const noexcept {
        if (ann_.access == ptr_access::read_only) {
            // 只读访问：使用 __ldg()（触发 ld.global.nc.* — 纹理缓存路径）
            return *const_cast<T*>(__ldg(ptr_));
        }
        if (ann_.restrict_) {
            // 无别名：告知编译器生成 ld.global（无额外 fence）
            T* __restrict__ rptr = ptr_;
            return *rptr;
        }
        return *ptr_;
    }

    __host__ __device__ T* get() const noexcept { return ptr_; }
    __host__ __device__ ptr_annotations annotations() const noexcept { return ann_; }
    __host__ __device__ explicit operator T*() const noexcept { return ptr_; }

private:
    T*              ptr_ = nullptr;
    ptr_annotations ann_{};
};

} // namespace world
```

#### 统一入口头文件

```cpp
// world/annotated_ptr
#pragma once

// 宿主侧：无设备关键字的轻量实现
// 设备侧：含 PTX 优化的完整实现
#ifdef __CUDA_ARCH__
#  include <world/detail/annotated_ptr_device.hpp>
#else
#  include <world/detail/annotated_ptr_host.hpp>
#endif

// 工厂函数（宿主+设备均可用）
namespace world {

template <typename T>
constexpr annotated_ptr<T> make_annotated(
    T* ptr,
    ptr_access access  = ptr_access::read_write,
    ptr_space space    = ptr_space::global,
    uint32_t alignment = alignof(T)) noexcept
{
    return annotated_ptr<T>(ptr, ptr_annotations{access, space, alignment});
}

template <typename T>
constexpr annotated_ptr<const T> make_read_only(T* ptr) noexcept {
    return annotated_ptr<const T>(
        ptr, ptr_annotations{ptr_access::read_only, ptr_space::global,
                              alignof(T)});
}

} // namespace world
```

#### 宿主代码使用示例

```cpp
// host_world_scheduler.cpp — 纯宿主代码，g++ 编译
#include <world/annotated_ptr>
#include <vector>

class WorldScheduler {
public:
    // 宿主侧持有设备指针 + 访问属性
    using IndividualStatePtr =
        world::annotated_ptr<world::individual_state>;

    void register_state(world::individual_state* dev_ptr, bool read_only) {
        auto ann = read_only
            ? world::make_read_only(dev_ptr)
            : world::make_annotated(dev_ptr,
                  world::ptr_access::read_write,
                  world::ptr_space::global, 128);
        state_ptrs_.push_back(ann);
    }

    // 根据访问属性决定 cudaMemcpy 方向和缓存策略
    void sync_states() {
        for (auto& ptr : state_ptrs_) {
            if (ptr.access() == world::ptr_access::read_only) {
                // 只读个体状态：仅需 Host→Device 方向同步
                cudaMemcpyAsync(ptr.get(), host_shadow_.data(),
                                sizeof(world::individual_state),
                                cudaMemcpyHostToDevice);
            }
        }
    }

private:
    ::std::vector<IndividualStatePtr> state_ptrs_;
    ::std::vector<world::individual_state> host_shadow_;
};
```

