## PRD: [BUG] 128-bit Integers Not Supported on Device Code

### 背景 / Background

在世界模型个体系统中，个体唯一标识符（Individual UUID）、世界状态时间戳（World State Timestamp）以及 IPU（SM）间的原子同步令牌均需要 128 位整数精度。然而，当前 `world::std`（原 `neuron::std`）的设备代码编译路径（`__world_device__` 函数）不支持 `__int128` / `uint128_t`，导致所有需要 128 位操作的 ISG（warp）级别内核无法编译，严重阻塞个体状态并行同步（TensorParallel）中的原子 CAS（Compare-And-Swap）操作。

### 问题复现

```cpp
// 当前代码在世界状态处理器（GPU）设备端触发编译错误
__world_device__ void update_individual_id(uint128_t* ids, uint128_t new_id) {
    // ERROR: 'uint128_t' is not supported in device code
    atomicCAS(ids, *ids, new_id);  // 128-bit atomic CAS
}

// 编译错误信息：
// error: identifier "uint128_t" is undefined in device code
// error: __int128 is not supported on this target
// note: in instantiation of world::std::atomic<__int128>
```

### 根因分析

1. **IPU（SM）架构限制**：早期 IPU 架构（Compute Capability < 7.0）不支持 128-bit 整数寄存器，编译器后端（PTX 生成器）未实现 `b128` 类型。
2. **`world::std` 类型系统缺口**：`world::std::numeric_limits` 未特化 `__int128`，`world::std::atomic<__int128>` 未实现设备端特化。
3. **软件模拟缺失**：无 `world::std::uint128_soft` 回退实现（双 64-bit 模拟）。

### 解决方案

#### 方案 A：原生 PTX b128 支持（IPU CC >= 8.0）

```cpp
// world/std/int128_device.hpp
#pragma once
#include <world/std/arch_detect.hpp>

#if defined(__WORLD_DEVICE__) && __WORLD_ARCH__ >= 800
// 原生 128-bit 支持（Ampere IPU 及以上）

namespace world::std {

struct alignas(16) uint128_t {
    uint64_t lo, hi;

    __world_device__ __world_forceinline__
    uint128_t(uint64_t lo_ = 0, uint64_t hi_ = 0) : lo(lo_), hi(hi_) {}

    // PTX-level 128-bit load（世界状态处理器原子读）
    __world_device__ __world_forceinline__
    static uint128_t atomic_load(const uint128_t* addr) {
        uint128_t result;
        asm volatile(
            "ld.acquire.gpu.b128 {%0, %1}, [%2];"
            : "=l"(result.lo), "=l"(result.hi)
            : "l"(addr)
            : "memory"
        );
        return result;
    }

    // PTX 128-bit CAS（IPU 间个体状态同步）
    __world_device__ __world_forceinline__
    static bool atomic_cas(uint128_t* addr,
                           uint128_t expected,
                           uint128_t desired) {
        uint64_t old_lo, old_hi;
        asm volatile(
            "atom.cas.b128 {%0, %1}, [%2], {%3, %4}, {%5, %6};"
            : "=l"(old_lo), "=l"(old_hi)
            : "l"(addr),
              "l"(expected.lo), "l"(expected.hi),
              "l"(desired.lo),  "l"(desired.hi)
            : "memory"
        );
        return (old_lo == expected.lo) && (old_hi == expected.hi);
    }
};

}  // namespace world::std

#else
// 方案 B：软件模拟（双 64-bit 回退，适用于旧 IPU）
#include <world/std/int128_soft.hpp>
#endif
```

#### 方案 B：软件模拟（world::std::int128_soft）

```cpp
// world/std/int128_soft.hpp
// 用于不支持原生 b128 的 IPU（SM）架构

namespace world::std {

struct alignas(16) uint128_soft {
    uint64_t lo, hi;

    __world_device__ __world_forceinline__
    uint128_soft operator+(const uint128_soft& rhs) const {
        uint128_soft result;
        result.lo = lo + rhs.lo;
        // 进位检测（ISG 内无分支实现）
        result.hi = hi + rhs.hi + (result.lo < lo ? 1ULL : 0ULL);
        return result;
    }

    __world_device__ __world_forceinline__
    bool operator==(const uint128_soft& rhs) const {
        return (lo == rhs.lo) && (hi == rhs.hi);
    }

    // 模拟 CAS（使用两次 64-bit atomicCAS，非原子但适用于 ISG 内同步）
    __world_device__
    static bool pseudo_cas(uint128_soft* addr,
                           uint128_soft expected,
                           uint128_soft desired) {
        // ISG（warp）级别：借助 warp-vote 保证一致性
        bool lo_ok = (atomicCAS(&addr->lo, expected.lo, desired.lo) == expected.lo);
        bool hi_ok = lo_ok &&
                     (atomicCAS(&addr->hi, expected.hi, desired.hi) == expected.hi);
        // 回滚（若 hi CAS 失败）
        if (lo_ok && !hi_ok) atomicCAS(&addr->lo, desired.lo, expected.lo);
        return hi_ok;
    }
};

// 类型别名：统一接口
#if __WORLD_ARCH__ >= 800
using uint128_t = world::std::uint128_t;   // 原生
#else
using uint128_t = world::std::uint128_soft; // 软件模拟
#endif

}  // namespace world::std
```

#### 单元测试

```cpp
