## PRD: [EPIC] Add Hopper Features to `neuron::ptx` (world::ptx)

### 背景 / Background

NVIDIA Hopper 架构（Compute Capability 9.0）引入了多项革命性硬件特性，这些特性在世界模型个体系统的映射框架下具有重要意义：

- **TMA（Tensor Memory Accelerator）**：异步批量数据搬运，直接映射为个体状态并行同步（TensorParallel）的高效数据加载路径
- **Warpgroup MMA（wgmma）**：4个 ISG（warp）协作的矩阵乘法单元，对应 ISG 群组（ISG Group）级别的协同计算
- **Distributed Shared Memory**：跨 IPU（SM）的共享内存直接访问，映射为个体间局部流水线传播（Local PipelineParallel）
- **Thread Block Cluster**：多 IPU 协作执行单元，对应世界运行时（Neuron_SP）的 IPU Cluster 调度原语
- **`cp.async.bulk`**：全局内存到共享内存的异步批量拷贝，映射为 TensorParallel 数据预取

本 EPIC 旨在将上述 Hopper 硬件特性封装为 `world::ptx`（原 `neuron::ptx`）命名空间下的高层抽象，使世界运行时能够透明地利用 Hopper IPU 的新能力加速个体群落计算。

### EPIC 范围（子 Feature 列表）

#### Feature 1：TMA 封装（world::ptx::tma）

```cpp
// world/ptx/tma.hpp
namespace world::ptx::tma {

// TMA 描述符：描述个体状态张量的内存布局
struct TensorMapDescriptor {
    void*    global_addr;     // 世界状态处理器全局内存地址
    uint32_t box_dim[5];      // 每次 TMA 传输的 box 尺寸
    uint32_t global_dim[5];   // 全局张量维度
    uint32_t element_stride;  // 元素步长

    // 在 host 端创建 TMA 描述符（Neuron_SP 控制线程）
    __world_host__
    static TensorMapDescriptor create_for_individual_state(
        void*   state_tensor,
        int64_t population_size,
        int64_t state_dim
    );
};

// ISG(warp) 内异步加载个体状态批次
// 映射：TensorParallel 数据预取 -> TMA cp.async.bulk
__world_device__
inline void async_load_individual_batch(
    world::std::SharedMemPtr<void> smem_dst,  // IPU(SM) 共享内存
    const TensorMapDescriptor& tmap,
    world::std::Coord2D coord,                 // (batch_id, feature_offset)
    world::ptx::MBarrier& barrier              // ISG 同步屏障
) {
    asm volatile(
        "cp.async.bulk.tensor.2d.shared::cluster.global.mbarrier::complete_tx::bytes"
        " [%0], [%1, {%2, %3}], [%4];"
        :
        : "r"(smem_dst.addr()),
          "l"(&tmap),
          "r"(coord.x), "r"(coord.y),
          "r"(barrier.addr())
        : "memory"
    );
}

// IPU Cluster 内分布式共享内存访问
__world_device__
inline void* get_distributed_smem_ptr(int peer_ipu_id, void* local_smem) {
    // Hopper distributed shared memory：跨 IPU 访问
    void* result;
    asm volatile(
        "mapa.shared::cluster.u64 %0, %1, %2;"
        : "=l"(result)
        : "l"(local_smem), "r"(peer_ipu_id)
    );
    return result;
}

}  // namespace world::ptx::tma
```

#### Feature 2：Warpgroup MMA（world::ptx::wgmma）

```cpp
// world/ptx/wgmma.hpp
// Warpgroup（4 ISG 协作）矩阵乘法：个体状态批量变换
namespace world::ptx::wgmma {

// wgmma.mma_async：4个 ISG 协作执行 16x8x16 矩阵乘法
// 映射：ISG Group 协同 -> 个体状态矩阵变换（TensorParallel 内）
template <int M, int N, int K>
__world_device__
inline void mma_async_f16_f32(
    world::ptx::RCArray<float, M*N/32>& d,    // 累加器（寄存器）
    const world::ptx::SharedMemPtr<__half>& a, // A 矩阵（共享内存）
    const world::ptx::RCArray<__half, K/8>& b, // B 矩阵（寄存器）
    bool scale_d = true
) {
    static_assert(M % 64 == 0, "wgmma M must be multiple of 64 (4 ISG * 16)");
    // PTX wgmma.mma_async 指令
    asm volatile(
        "wgmma.mma_async.sync.aligned.m64n%0k16.f32.f16.f16"
        " %1, %2, %3, %4, 1, 1;"
        : "+f"(d[0])  // 输出累加器
        : "n"(N),
          "l"(a.addr()),     // A: shared memory
          "r"(b[0]),         // B: register file
          "n"(scale_d ? 1 : 0)
        : "memory"
    );
}

// wgmma fence：确保 ISG Group 内 wgmma 操作有序
__world_device__
inline void fence() {
    asm volatile("wgmma.fence.sync.aligned;" ::: "memory");
}

__world_device__
inline void commit_group() {
    asm volatile("wgmma.commit_group.sync.aligned;" ::: "memory");
}

__world_device__
inline void wait_group(int n = 0) {
    asm volatile("wgmma.wait_group.sync.aligned %0;" :: "n"(n) : "memory");
}

}  // namespace world::ptx::wgmma
```

#### Feature 3：MBarrier（world::ptx::mbarrier）

```cpp
// world/ptx/mbarrier.hpp
// Hopper MBarrier：ISG 间精确同步，替代旧版 __syncthreads
namespace world::ptx::mbarrier {

// MBarrier 初始化（由 host 或 IPU 主 ISG 执行）
__world_device__
inline void init(uint64_t* barrier, int expected_tx_bytes) {
    asm volatile(
        "mbarrier.init.shared::cta.b64 [%0], %1;"
        :: "r"(barrier), "r"(expected_tx_bytes)
        : "memory"
    );
}

// 等待 TMA 异步传输完成（ISG 级别阻塞等待）
__world_device__
inline void wait_tma_complete(uint64_t* barrier, int phase) {
    asm volatile(
        "{
"
        "  .reg .pred P;
"
        "  LAB_WAIT:
"
        "  mbarrier.try_wait.parity.shared::cta.b64 P, [%0], %1;
"
        "  @!P bra LAB_WAIT;
"
        "}
"
        :: "r"(barrier), "r"(phase)
        : "memory"
    );
}

// arrive（ISG 完成本地工作，通知 barrier）
__world_device__
inline void arrive(uint64_t* barrier) {
    asm volatile(
        "mbarrier.arrive.shared::cta.b64 _, [%0];"
        :: "r"(barrier)
        : "memory"
    );
}

}  // namespace world::ptx::mbarrier
```

#### Feature 4：Thread Block Cluster（world::ptx::cluster）

```cpp
