// IPU Cluster：Hopper 多 IPU 协作单元
// 映射：世界运行时 IPU Cluster -> 局部个体间流水线传播
namespace world::ptx::cluster {

// 获取 cluster 内 IPU 块 ID（用于分布式内存寻址）
__world_device__
inline int block_id_in_cluster() {
    int id;
    asm volatile("mov.u32 %0, %%cluster_ctaid.x;" : "=r"(id));
    return id;
}

// cluster barrier：同步 cluster 内所有 IPU 块
__world_device__
inline void barrier_arrive() {
    asm volatile("barrier.cluster.arrive;" ::: "memory");
}

__world_device__
inline void barrier_wait() {
    asm volatile("barrier.cluster.wait;" ::: "memory");
}

// cluster 尺寸查询
__world_device__
inline int cluster_size() {
    int sz;
    asm volatile("mov.u32 %0, %%cluster_nctaid.x;" : "=r"(sz));
    return sz;
}

}  // namespace world::ptx::cluster
```

