### Automated Migration Script

```python
#!/usr/bin/env python3
# scripts/replace_tp_tuple.py
import re, sys
from pathlib import Path

def classify_file(path):
    content = path.read_text()
    has_device = bool(re.search(r'__device__|__global__|__shared__', content))
    has_host   = bool(re.search(r'int main|::std::|std::vector', content))
    if has_device and not has_host:
        return 'device'
    elif has_device and has_host:
        return 'mixed'
    return 'host'

def migrate_tuple(path):
    content = path.read_text()
    file_type = classify_file(path)
    replacement = {
        'device': 'world::std::device_tuple',
        'mixed':  'world::std::tuple',
        'host':   'world::std::tuple',
    }[file_type]

    original = content
    content = re.sub(r' tensor_parallel::tuple ', replacement, content)
    content = re.sub(
        r'#include\s+[<"]tensor_parallel/tuple\.hpp[>"]',
        '#include <world/std/api_types.hpp>',
        content
    )
    # Fix companion thrust::get -> world::std::get
    content = re.sub(r' thrust::get<(\d+)>\(', r'world::std::get<>(', content)

    if content != original:
        path.write_text(content)
        print(f"[{file_type:7s}] {path.name}")
        return 1
    return 0

if __name__ == "__main__":
    root = Path(sys.argv[1] if len(sys.argv) > 1 else ".")
    total = 0
    for ext in ["*.hpp", "*.cpp", "*.cuh", "*.cu"]:
        for f in root.rglob(ext):
            total += migrate_tuple(f)
    print(f"Migrated {total} files")
```

