## PRD: [FEA] Add an Owning Stream Wrapper

### Background

In the World Model Individual System, `world::std::Stream` (the compute stream abstraction for world-state-processors / GPU) is currently a **non-owning wrapper** around a raw `cudaStream_t` handle. This means:

1. **Lifetime management is manual**: Every component in the world runtime (Neuron_SP) that creates a stream must also remember to destroy it, leading to stream leaks in error paths.
2. **No RAII**: When a PipelineParallel (individual inter-pipeline propagation) stage object is destroyed, its associated stream is not automatically cleaned up.
3. **TensorParallel synchronization hazard**: When individual state parallel sync (TensorParallel) contexts are copied or moved, the underlying `cudaStream_t` may be destroyed prematurely or double-freed.
4. **Inconsistent ownership semantics**: Some APIs take `cudaStream_t` directly, others take `world::std::Stream`, making it unclear who owns the underlying resource.

This Feature introduces `world::std::OwnedStream` - a fully RAII-compliant, move-only owning wrapper around `cudaStream_t`, alongside a non-owning `world::std::StreamView` for non-owning references, following the same ownership model as `std::unique_ptr` vs raw pointer.

### Design

#### Ownership Model

```
world::std::OwnedStream   - owns the cudaStream_t (like std::unique_ptr)
world::std::StreamView    - non-owning reference (like raw pointer / std::span)
world::std::Stream        - alias for StreamView (backward compat)
```

#### Core API

```cpp
// world/std/stream.hpp
#pragma once
#include <cuda_runtime.h>
#include <world/std/error.hpp>

namespace world::std {

// ============================================================
// StreamView: non-owning reference to a cudaStream_t
// (replaces the current world::std::Stream)
// ============================================================
class StreamView {
public:
    // Implicit construction from raw CUDA stream (backward compat)
    StreamView(cudaStream_t stream = nullptr) noexcept : stream_(stream) {}

    // Access underlying handle
    cudaStream_t get() const noexcept { return stream_; }
    operator cudaStream_t() const noexcept { return stream_; }

    // Synchronize: block until all work on this stream completes
    // Used by Neuron_SP (world runtime) control thread
    __world_host__
    void synchronize() const {
        WORLD_CUDA_CHECK(cudaStreamSynchronize(stream_));
    }

    // Query: non-blocking check if stream work is complete
    __world_host__
    bool query() const {
        cudaError_t err = cudaStreamQuery(stream_);
        if (err == cudaSuccess) return true;
        if (err == cudaErrorNotReady) return false;
        WORLD_CUDA_CHECK(err);
        return false;
    }

    // Record event on this stream (for PipelineParallel inter-stage sync)
    __world_host__
    void record_event(cudaEvent_t event) const {
        WORLD_CUDA_CHECK(cudaEventRecord(event, stream_));
    }

    // Wait for event from another stream (cross-IPU synchronization)
    __world_host__
    void wait_event(cudaEvent_t event) const {
        WORLD_CUDA_CHECK(cudaStreamWaitEvent(stream_, event, 0));
    }

    bool operator==(const StreamView& rhs) const noexcept {
        return stream_ == rhs.stream_;
    }

    bool is_null() const noexcept { return stream_ == nullptr; }

private:
    cudaStream_t stream_;
};

// Default stream (stream 0) - used when no explicit stream is provided
inline StreamView default_stream() noexcept { return StreamView{nullptr}; }

// ============================================================
// OwnedStream: RAII owning wrapper (move-only)
// ============================================================
class OwnedStream {
public:
    // Create a new CUDA stream with specified flags
    // priority: stream scheduling priority for world-state-processor
    explicit OwnedStream(
        unsigned int flags    = cudaStreamNonBlocking,
        int          priority = 0
    ) {
        if (priority == 0) {
            WORLD_CUDA_CHECK(cudaStreamCreateWithFlags(&stream_, flags));
        } else {
            WORLD_CUDA_CHECK(cudaStreamCreateWithPriority(&stream_, flags, priority));
        }
    }

    // Non-copyable (unique ownership)
    OwnedStream(const OwnedStream&)            = delete;
    OwnedStream& operator=(const OwnedStream&) = delete;

    // Movable
    OwnedStream(OwnedStream&& other) noexcept
        : stream_(other.stream_) { other.stream_ = nullptr; }

    OwnedStream& operator=(OwnedStream&& other) noexcept {
        if (this != &other) {
            destroy();
            stream_ = other.stream_;
            other.stream_ = nullptr;
        }
        return *this;
    }

    // RAII destructor: automatically destroy stream
    ~OwnedStream() { destroy(); }

    // Get non-owning view (for passing to APIs that take StreamView)
    StreamView view() const noexcept { return StreamView{stream_}; }
    operator StreamView() const noexcept { return view(); }

    // Direct access
    cudaStream_t get() const noexcept { return stream_; }
    operator cudaStream_t() const noexcept { return stream_; }

    // Release ownership (caller takes responsibility for destruction)
    [[nodiscard]]
    cudaStream_t release() noexcept {
        cudaStream_t s = stream_;
        stream_ = nullptr;
        return s;
    }

    // Adopt existing stream (take ownership)
    static OwnedStream adopt(cudaStream_t stream) noexcept {
        OwnedStream s;
        s.stream_ = stream;
        return s;
    }

    // Forwarded StreamView methods
    void synchronize() const { view().synchronize(); }
    bool query()       const { return view().query(); }
    void record_event(cudaEvent_t e) const { view().record_event(e); }
    void wait_event(cudaEvent_t e)   const { view().wait_event(e); }

private:
    OwnedStream() noexcept : stream_(nullptr) {}  // private default for adopt()

    void destroy() noexcept {
        if (stream_ != nullptr) {
            cudaStreamDestroy(stream_);  // ignore error in destructor
            stream_ = nullptr;
        }
    }

    cudaStream_t stream_ = nullptr;
};

// Backward compat alias
using Stream = StreamView;

// ============================================================
// StreamPool: pool of OwnedStreams for world-runtime reuse
// Used by Neuron_SP to avoid repeated stream creation overhead
// ============================================================
class StreamPool {
public:
    explicit StreamPool(int pool_size = 8, unsigned int flags = cudaStreamNonBlocking) {
        streams_.reserve(pool_size);
        for (int i = 0; i < pool_size; ++i) {
            streams_.emplace_back(flags);
        }
    }

    // Get stream by index (non-owning)
    StreamView operator[](int i) const { return streams_[i].view(); }
    int size() const { return static_cast<int>(streams_.size()); }

    // Round-robin stream assignment (for ISG-parallel kernel launches)
    StreamView next() {
        return streams_[next_idx_++ % streams_.size()].view();
    }

private:
    ::std::vector<OwnedStream> streams_;
    int next_idx_ = 0;
};

}  // namespace world::std
```

#### Usage Examples

```cpp
// Example 1: PipelineParallel stage with RAII stream
class PipelineStage {
public:
    PipelineStage()
        : stream_(cudaStreamNonBlocking)  // OwnedStream: auto-destroyed with stage
    {}

    void execute(const IndividualBatch& batch) {
        // Launch kernel on owned stream
        process_individual_batch<<<grid, block, 0, stream_.get()>>>(batch);
    }

    // Wait for this stage to complete (for next PipelineParallel stage)
    void synchronize() { stream_.synchronize(); }

    // Pass non-owning view to downstream stage
    world::std::StreamView stream_view() const { return stream_.view(); }

private:
    world::std::OwnedStream stream_;  // RAII: destroyed when PipelineStage dies
};

// Example 2: TensorParallel with stream pool
class TensorParallelContext {
public:
    TensorParallelContext(int num_gpus)
        : sync_stream_pool_(num_gpus)  // one stream per world-state-processor
    {}

    world::std::StreamView get_sync_stream(int gpu_id) {
        return sync_stream_pool_[gpu_id];
    }

private:
    world::std::StreamPool sync_stream_pool_;
};

// Example 3: Adopt existing legacy cudaStream_t
cudaStream_t legacy_stream;
cudaStreamCreate(&legacy_stream);
{
    auto owned = world::std::OwnedStream::adopt(legacy_stream);
    // stream is now managed; will be destroyed when 'owned' goes out of scope
    kernel<<<grid, block, 0, owned.get()>>>(data);
}  // legacy_stream automatically destroyed here
```

