    typename KeyT,
    typename ValueT,
    typename OffsetIteratorT,
    typename CompareOpT = world::std::less<KeyT>
>
struct DeviceSegmentedSort {

    // 原有接口保持兼容
    static world::std::error_code SortPairs(/* ... */);

    // 新增：自定义比较器版本
    template <typename CompareOp = CompareOpT>
    static world::std::error_code SortPairsBy(
        void*             d_temp_storage,
        size_t&           temp_storage_bytes,
        const KeyT*       d_keys_in,
        KeyT*             d_keys_out,
        const ValueT*     d_values_in,
        ValueT*           d_values_out,
        int               num_items,
        int               num_segments,
        OffsetIteratorT   d_begin_offsets,
        OffsetIteratorT   d_end_offsets,
        CompareOp         compare_op = CompareOp{},
        world_stream_t    stream = 0
