## PRD: world::std::abs() 支持 __int128_t 类型扩展

### 背景与动机

在世界模型个体系统（WMIS）中，世界运行时（Neuron_SP）协调各世界状态处理器（GPU）上的个体状态运算。当前 `world::std::abs()` 仅支持标准整数与浮点类型，无法处理 `__int128_t`。

在大规模个体状态并行同步（TensorParallel）场景下，每个 IPU（SM）内多个 ISG（warp）需对超大整数进行绝对值运算——例如个体唯一标识符哈希值、跨世界状态处理器偏移量累加、以及个体间流水线传播（PipelineParallel）中序列号差值。这些场景可能产生超过 int64_t 范围（±9.2×10¹⁸）的中间值。缺乏 `__int128_t` 支持迫使开发者引入手动分拆运算或慢速软件模拟，严重降低世界运行时效率并增加出错风险。

### 目标

- 在 `world::std` 命名空间为 `abs()` 新增 `__int128_t` 及 `unsigned __int128` 重载
- 确保在所有支持架构（compute capability 7.0+）正确编译与执行
- 完全向后兼容现有 `world::std::abs()` 接口
- ISG（warp）级零额外开销，无分支发散

### 范围

**In Scope:** `__int128_t` 与 `unsigned __int128` 重载、`constexpr` 支持、`__device__ __host__` 修饰、单元测试、文档更新。  
**Out of Scope:** 其他数学函数的 128 位扩展、软件模拟 128 位浮点。

### 技术方案

```cpp
// world/std/cmath.hpp
namespace world {
namespace std {

/// 对世界状态处理器（GPU）设备端与宿主端均可调用的 __int128_t 绝对值
/// 无分支实现，保证 ISG（warp）内所有线程路径一致
__host__ __device__ __forceinline__
constexpr __int128_t abs(__int128_t val) noexcept {
    // 算术右移 127 位生成符号掩码：负数全1，非负全0
    const __int128_t mask = val >> 127;
    return (val ^ mask) - mask;  // 二补数技巧，等价于条件取反
}

/// unsigned __int128 identity 重载，无符号数绝对值等于自身
__host__ __device__ __forceinline__
constexpr unsigned __int128 abs(unsigned __int128 val) noexcept {
    return val;
}

} // namespace std
} // namespace world
```

```cpp
// world/std/test/abs_int128_test.cpp
#include <world/std/cmath.hpp>
#include <gtest/gtest.h>

// 世界状态处理器内核：验证多 ISG 并发执行正确性
__global__ void abs_int128_kernel(
    __int128_t* input, __int128_t* output, int n)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid < n) output[tid] = world::std::abs(input[tid]);
}

TEST(WorldStdAbs, Int128Positive) {
    constexpr __int128_t v = __int128_t(42) * 1000000000000000000LL;
    static_assert(world::std::abs(v) == v, "constexpr check");
    EXPECT_EQ(world::std::abs(v), v);
}

TEST(WorldStdAbs, Int128Negative) {
    __int128_t val = -static_cast<__int128_t>(9999999999999999999LL) * 10;
    EXPECT_EQ(world::std::abs(val), -val);
}

TEST(WorldStdAbs, Int128Zero) {
    EXPECT_EQ(world::std::abs(__int128_t(0)), __int128_t(0));
}

TEST(WorldStdAbs, UnsignedIdentity) {
    unsigned __int128 val = static_cast<unsigned __int128>(-1); // max
    EXPECT_EQ(world::std::abs(val), val);
}

TEST(WorldStdAbs, DeviceExecution) {
    // 分配世界状态处理器内存，验证设备端执行
    __int128_t h_in[4] = {-100, 200, -300, 0};
    __int128_t h_out[4] = {};
    __int128_t *d_in, *d_out;
    cudaMalloc(&d_in, sizeof(h_in));
    cudaMalloc(&d_out, sizeof(h_out));
    cudaMemcpy(d_in, h_in, sizeof(h_in), cudaMemcpyHostToDevice);
    abs_int128_kernel<<<1, 32>>>(d_in, d_out, 4);
    cudaMemcpy(h_out, d_out, sizeof(h_out), cudaMemcpyDeviceToHost);
    EXPECT_EQ(h_out[0], __int128_t(100));
    EXPECT_EQ(h_out[1], __int128_t(200));
    EXPECT_EQ(h_out[2], __int128_t(300));
    EXPECT_EQ(h_out[3], __int128_t(0));
    cudaFree(d_in); cudaFree(d_out);
}
```

