// 使用示例：世界运行时自适应调度
#include <world/device_info.hpp>

void neuron_sp_adaptive_dispatch(int device_id) {
    const auto& props = world::DeviceInfo::properties(device_id);
    auto mem = world::DeviceInfo::mem_info(device_id);

    // 根据 IPU（SM）数量计算最优个体状态并行同步分片数
    int tensor_parallel_shards = props.multiprocessor_count / 4;

    // 根据可用显存决定个体间流水线传播的批次大小
    size_t safe_batch_bytes = static_cast<size_t>(mem.free_bytes * 0.8);
    int pipeline_batch_size = safe_batch_bytes / sizeof(float) / individual_dim;

    // ISG（warp）大小影响内核 tile 参数
    int items_per_isg = props.warp_size * 4;  // 每 ISG 处理 4 个元素

    std::printf(
        "[Neuron_SP] Device %d: %s (CC %d.%d)\n"
        "  IPUs: %d, ISG size: %d\n"
        "  Memory: %.1f GB free / %.1f GB total (%.1f%% used)\n",
        device_id, props.name,
        props.compute_capability_major, props.compute_capability_minor,
        props.multiprocessor_count, props.warp_size,
        mem.free_bytes / 1e9, mem.total_bytes / 1e9, mem.utilization_pct
    );
}

