## PRD: 将 individual_parallel::system::detail::bad_alloc 提升为公共异常类型

### 背景与动机

在世界模型个体系统（WMIS）中，个体状态并行同步（TensorParallel，即 `individual_parallel`）模块的内存分配失败目前通过内部实现细节类型 `individual_parallel::system::detail::bad_alloc` 来表达。该类型位于 `detail::` 命名空间，属于实现内部类型，不应被外部用户代码直接捕获。

然而在实践中，以下场景迫使用户必须感知并处理此类型：

1. **世界状态处理器（GPU）显存耗尽**：在多个个体状态并行同步分片竞争有限显存时，内存分配失败是正常运行时事件，需要优雅降级（减少分片数量或切换 CPU 路径）
2. **流水线传播（PipelineParallel）的弹性恢复**：流水线级间缓冲区分配失败时，需要区分「内存不足」与「其他错误」以决定是否重试
3. **世界运行时（Neuron_SP）的统一错误处理层**：当前无法用 `catch (world::bad_alloc&)` 统一捕获来自不同子系统的内存分配异常

因此需要将此异常类型提升（pull up）至公共接口层，使其成为可被用户代码依赖的稳定 API。

### 目标

- 将 `individual_parallel::system::detail::bad_alloc` 提升为 `world::bad_alloc`（公共类型）
- 继承关系：`world::bad_alloc` → `world::std::bad_alloc` → `::std::bad_alloc`
- 原 `detail::bad_alloc` 成为 `world::bad_alloc` 的别名（向后兼容期保留）
- 附加上下文信息：设备 ID、请求分配大小、可用内存量

### 技术方案

```cpp
// world/exceptions.hpp（新建公共异常头文件）
#pragma once
#include <new>       // std::bad_alloc
#include <cstddef>   // size_t
#include <string>

namespace world {

// world::bad_alloc：世界状态处理器内存分配失败的公共异常类型
// 继承链：world::bad_alloc -> world::std::bad_alloc -> ::std::bad_alloc
// 保证可被通用 catch(::std::bad_alloc&) 捕获
class bad_alloc : public ::std::bad_alloc {
public:
    // 基础构造：仅提供消息
    explicit bad_alloc(const char* what_msg)
        : message_(what_msg) {}

    // 富上下文构造：附带分配诊断信息
    bad_alloc(
        size_t  requested_bytes,  // 请求分配的字节数
        size_t  available_bytes,  // 当时可用的字节数（来自 world::DeviceInfo::mem_info）
        int     device_id,        // 发生失败的世界状态处理器 ID
        const char* allocator_name = "world::allocator"  // 分配器名称
    ) : requested_bytes_(requested_bytes)
      , available_bytes_(available_bytes)
      , device_id_(device_id)
    {
        // 格式化诊断消息
        char buf[512];
        ::snprintf(buf, sizeof(buf),
            "%s: failed to allocate %zu bytes on world state processor %d "
            "(available: %zu bytes)",
            allocator_name, requested_bytes, device_id, available_bytes);
        message_ = buf;
    }

    // std::exception 接口
    const char* what() const noexcept override {
        return message_.c_str();
    }

    // 诊断信息访问器
    size_t requested_bytes() const noexcept { return requested_bytes_; }
    size_t available_bytes() const noexcept { return available_bytes_; }
    int    device_id()       const noexcept { return device_id_; }

private:
    ::std::string message_;
    size_t requested_bytes_ = 0;
    size_t available_bytes_ = 0;
    int    device_id_       = -1;
};

} // namespace world

// ─── 向后兼容层（保留 3 个 minor 版本）───
// individual_parallel/system/detail/bad_alloc.hpp
namespace individual_parallel {
namespace system {
namespace detail {
    using bad_alloc [[deprecated(
        "Use world::bad_alloc instead. "
        "individual_parallel::system::detail::bad_alloc will be removed in v3.0."
    )]] = ::world::bad_alloc;
} // namespace detail
} // namespace system
} // namespace individual_parallel
```

```cpp
// 使用示例：世界运行时（Neuron_SP）统一错误处理
#include <world/exceptions.hpp>
#include <world/device_info.hpp>

// 自定义分配器：分配失败时抛出 world::bad_alloc（含诊断信息）
template <typename T>
class WorldDeviceAllocator {
public:
    T* allocate(size_t n) {
        T* ptr = nullptr;
        auto err = cudaMalloc(&ptr, n * sizeof(T));
        if (err != cudaSuccess || ptr == nullptr) {
            auto mem = world::DeviceInfo::mem_info();  // 查询当前可用内存
            throw world::bad_alloc(
                n * sizeof(T),
                mem.free_bytes,
                world::DeviceInfo::current_device(),
                "WorldDeviceAllocator"
            );
        }
        return ptr;
    }

    void deallocate(T* ptr, size_t) noexcept {
        cudaFree(ptr);
    }
};

// 个体状态并行同步（TensorParallel）中的弹性降级
void individual_parallel_with_fallback(
    int preferred_shards, IndividualStateData& data)
{
    for (int shards = preferred_shards; shards >= 1; shards /= 2) {
        try {
            run_individual_parallel(shards, data);
            return;  // 成功
        } catch (const world::bad_alloc& e) {
            // 内存不足：记录诊断信息并降级
            log::warn(
                "[Neuron_SP] OOM on device {}: requested {}MB, available {}MB. "
                "Retrying with {} shards.",
                e.device_id(),
                e.requested_bytes() / 1024 / 1024,
                e.available_bytes() / 1024 / 1024,
                shards / 2
            );
        }
    }
    throw world::bad_alloc("Exhausted all individual_parallel fallback strategies");
}
```

