## PRD: 带属性约束的非拥有视图类型，确保世界状态处理器内存的类型安全访问

### 背景与动机

在世界模型个体系统（WMIS）中，个体状态数据在不同执行阶段需要被多个组件共享访问：
世界运行时（Neuron_SP）调度器持有所有权，IPU（SM）内的 ISG（warp）持有只读计算视图，个体状态并行同步（TensorParallel）持有分布式分片视图，个体间流水线传播（PipelineParallel）的阶段边界持有临时可写视图。

当前代码库通过裸指针 + 长度参数传递这些视图，存在严重的类型安全问题：

- **内存空间混淆**：将宿主内存指针误传入 ISG 内核，或将设备内存指针在宿主侧解引用，  这类错误只在运行时（通过 `worldErrorIllegalAddress`）才会暴露
- **只读/可写混淆**：接受 `T*` 的函数可能意外修改只读数据，破坏个体状态不变量
- **生命周期不透明**：视图的有效期依赖隐式约定，易产生悬空指针
- **维度/形状信息丢失**：多维个体状态张量退化为平坦指针，维度语义需额外注释

### 目标

- 设计 `world::view<T, Properties...>` 非拥有视图类型，通过模板属性编码访问约束
- 属性包含：内存空间（host/device/unified）、访问权限（read-only/read-write）、  对齐要求、维度信息
- 编译期强制约束：空间不匹配、权限违反在编译期报错而非运行时崩溃
- 与 `world::vector` 无缝集成，支持从拥有容器隐式创建视图

### 技术方案

```cpp
// world/view.hpp
#pragma once
#include <world/memory_spaces.hpp>
#include <world/access_modes.hpp>

namespace world {

// ─── 属性标签类型 ───
namespace prop {

// 内存空间属性（对应世界状态处理器内存层次）
template <typename MemSpace> struct memory_space { using type = MemSpace; };

// 访问模式属性
struct read_only  {};  // 只读：ISG（warp）计算内核的输入
struct read_write {};  // 可读可写：流水线传播的中间缓冲

// 对齐属性（影响向量化加载指令选择）
template <size_t Align> struct aligned { static constexpr size_t value = Align; };

// 维度属性（静态或动态）
template <size_t... Dims> struct shape {};   // 静态维度
struct dynamic_shape {};                     // 动态维度（运行时确定）

} // namespace prop

// ─── 主视图模板 ───
template <typename T, typename... Properties>
class view {
public:
    using value_type = T;

    // 从原始指针构造（世界运行时内部使用）
    __host__ __device__
    view(T* ptr, size_t size) noexcept
        : ptr_(ptr), size_(size) {}

    // 从 world::vector 隐式构造（安全：生命周期由 vector 保证）
    template <typename MemSpace>
    view(world::vector<T, MemSpace>& v) noexcept
        requires check_memory_space_compat<MemSpace, Properties...>
        : ptr_(v.data()), size_(v.size()) {}

    // const 版本（用于 read_only 视图）
    template <typename MemSpace>
    view(const world::vector<T, MemSpace>& v) noexcept
        requires (has_property<prop::read_only, Properties...>)
        : ptr_(const_cast<T*>(v.data())), size_(v.size()) {}

    // 元素访问（仅 host/unified 内存，read-write 或 read-only）
    __host__
    T& operator[](size_t i)
        requires (has_property<prop::read_write, Properties...> &&
                  !has_device_only_space<Properties...>);

    __host__
    const T& operator[](size_t i) const
        requires (!has_device_only_space<Properties...>);

    // 设备端访问（ISG 内核使用）
    __device__
    T& operator[](size_t i)
        requires (has_property<prop::read_write, Properties...> &&
                  !has_host_only_space<Properties...>);

    // 原始指针（世界状态处理器内核调用）
    __host__ __device__
    T*       data()       noexcept { return ptr_; }
    __host__ __device__
    const T* data() const noexcept { return ptr_; }

    __host__ __device__
    size_t size() const noexcept { return size_; }

    __host__ __device__
    bool empty() const noexcept { return size_ == 0; }

    // 子视图切片
    __host__ __device__
    view<T, Properties...> subview(size_t offset, size_t count) const noexcept;

    // 降级为只读视图（允许 read_write -> read_only 隐式转换）
    operator view<T, prop::read_only, /* 其他 Properties... */>() const noexcept;

private:
    T*     ptr_;
    size_t size_;
};

// ─── 常用视图别名 ───
template <typename T>
using device_view = view<T,
    prop::memory_space<device_memory>,
    prop::read_write>;

template <typename T>
using device_view_ro = view<T,
    prop::memory_space<device_memory>,
    prop::read_only>;

template <typename T>
using host_view = view<T,
    prop::memory_space<host_memory>,
    prop::read_write>;

template <typename T>
using host_view_ro = view<T,
    prop::memory_space<host_memory>,
    prop::read_only>;

} // namespace world
```

```cpp
// 使用示例：ISG（warp）内核类型安全访问
#include <world/view.hpp>

// 内核仅接受设备只读视图作为输入——编译期保证不会意外修改
__global__ void isg_compute_kernel(
    world::device_view_ro<float> individual_states,  // 只读输入
    world::device_view<float>    output_buffer)      // 可写输出
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid < (int)individual_states.size()) {
        // individual_states[tid] = 0.f;  // 编译错误：read_only 不允许写入
        output_buffer[tid] = individual_states[tid] * 2.f;  // OK
    }
}

// 世界运行时（Neuron_SP）调度：从拥有容器创建视图
void neuron_sp_dispatch(
    world::device_vector<float>& states,  // 拥有容器
    world::device_vector<float>& output)
{
    // 隐式从 device_vector 创建只读视图（编译期检查内存空间匹配）
    world::device_view_ro<float> states_view(states);
    world::device_view<float>    output_view(output);

    // 将视图传入 ISG 内核（而非裸指针）
    isg_compute_kernel<<<1024, 256>>>(states_view, output_view);

    // 编译错误示例（尝试将宿主视图传入设备内核）
    // world::host_view<float> wrong_view(states);  // 空间不匹配，编译错误
}
```

### Sub-tasks

1. **ST-1**: 设计并实现属性标签类型（`prop::memory_space`、`prop::read_only`、`prop::read_write`、`prop::aligned`）
2. **ST-2**: 实现 `world::view<T, Properties...>` 主模板，含内存空间与访问模式的编译期约束 concepts
3. **ST-3**: 实现从 `world::vector` 到 `world::view` 的隐式转换，含空间匹配检查
