## PRD: world::span<T, Properties...> — 异构内存空间的安全连续序列视图

### 背景与动机

在世界模型个体系统（WMIS）中，个体状态数据跨越多种内存层次流转：世界运行时（Neuron_SP）宿主侧的系统内存、世界状态处理器（GPU）的高带宽设备内存、IPU（SM）内的共享内存，以及统一内存寻址空间。不同的个体状态并行同步（TensorParallel）分片与个体间流水线传播（PipelineParallel）阶段需要在这些空间中传递连续内存视图。

C++20 的 `std::span<T>` 提供了连续内存的非拥有视图，但完全不感知内存空间，导致以下问题：

- 将设备内存 span 传递给宿主侧代码，在 ISG（warp）外部解引用导致 `worldErrorIllegalAddress`
- 将只读共享内存 span 作为可写输出参数传入，破坏 IPU 级不变量
- 不同对齐要求的 span 被统一处理，错失向量化加载（LDG.128）优化机会
- 异构内存中的个体状态向量（`IndividualStateVec`）与标量（`float`）  span 可相互隐式转换，引入类型混淆

`world::span<T, Properties...>` 通过编译期属性系统解决上述问题，同时兼容 `std::span` 的基本接口以降低迁移成本。

### 目标

- `world::span<T, Properties...>` 在 `std::span<T>` 基础上附加内存空间、  访问模式、对齐、所属 ISG 等属性，全部在编译期检查
- 支持静态（`world::static_extent`）与动态（`world::dynamic_extent`）大小
- 支持 `__host__` / `__device__` 双端使用（属性决定哪端可调用哪些成员）
- 与 `world::view` 及 `world::vector` 生态系统无缝集成

### 技术方案

```cpp
// world/span.hpp
#pragma once
#include <world/view.hpp>     // 复用属性标签
#include <cstddef>

namespace world {

// 大小标记
inline constexpr size_t dynamic_extent = SIZE_MAX;

// ─── world::span 主模板 ───
template <
    typename T,
    size_t Extent = dynamic_extent,
    typename... Properties    // 属性包：memory_space, access_mode, aligned, ...
>
class span {
public:
    using element_type    = T;
    using value_type      = ::std::remove_cv_t<T>;
    using size_type       = size_t;
    using difference_type = ptrdiff_t;
    using pointer         = T*;
    using const_pointer   = const T*;
    using reference       = T&;
    using const_reference = const T&;

    static constexpr size_t extent = Extent;

    // ─── 构造 ───
    // 默认：空 span
    __host__ __device__
    constexpr span() noexcept requires (Extent == 0 || Extent == dynamic_extent)
        : ptr_(nullptr), size_(0) {}

    // 从指针 + 大小构造
    __host__ __device__
    constexpr span(T* ptr, size_t count) noexcept
        : ptr_(ptr), size_(count) {
        WORLD_ASSERT(Extent == dynamic_extent || count == Extent);
    }

    // 从静态数组构造（宿主端常用，加载配置参数）
    template <size_t N>
    __host__
    constexpr span(T (&arr)[N]) noexcept
        requires (Extent == dynamic_extent || N == Extent)
        : ptr_(arr), size_(N) {}

    // 从 world::vector 构造（检查内存空间属性匹配）
    template <typename MemSpace>
    span(world::vector<T, MemSpace>& v)
        requires memory_space_matches<MemSpace, Properties...>
        : ptr_(v.data()), size_(v.size()) {}

    // 从 world::view 构造
    template <typename... ViewProps>
    span(world::view<T, ViewProps...> v)
        requires properties_subset<ViewProps..., Properties...>
        : ptr_(v.data()), size_(v.size()) {}

    // ─── 元素访问 ───
    // 设备内存：仅在 __device__ 上下文访问
    __device__
    reference operator[](size_type i) const noexcept
        requires has_device_space<Properties...>;

    // 宿主内存：仅在 __host__ 上下文访问
    __host__
    reference operator[](size_type i) const noexcept
        requires (!has_device_only_space<Properties...>);

    // 统一内存：双端均可访问
    __host__ __device__
    reference operator[](size_type i) const noexcept
        requires has_unified_space<Properties...>;

    __host__ __device__ constexpr T*     data()  const noexcept { return ptr_; }
    __host__ __device__ constexpr size_t size()  const noexcept { return size_; }
    __host__ __device__ constexpr bool   empty() const noexcept { return size_ == 0; }

    // ─── 子 span ───
    // first<N>：静态大小前缀子 span
    template <size_t N>
    __host__ __device__
    constexpr span<T, N, Properties...> first() const noexcept;

    // last<N>：静态大小后缀子 span
    template <size_t N>
    __host__ __device__
    constexpr span<T, N, Properties...> last() const noexcept;

    // subspan：动态子 span
    __host__ __device__
    constexpr span<T, dynamic_extent, Properties...>
    subspan(size_t offset, size_t count = dynamic_extent) const noexcept;

    // ─── 跨 ISG（warp）分块 ───
    // 将 span 均匀分配给 ISG，返回当前 ISG 对应的子 span
    __device__
    span<T, dynamic_extent, Properties...>
    isg_partition(int isg_id, int total_isgs) const noexcept;

    // ─── 类型重解释（异构内存场景）───
    // reinterpret_as<U>：将 T span 重解释为 U span，需显式标注
    template <typename U>
    __host__ __device__
    span<U, dynamic_extent, Properties...>
    reinterpret_as(world::unsafe_reinterpret_tag) const noexcept;

private:
    T*     ptr_;
    size_t size_;
};

// ─── 常用别名 ───
template <typename T, size_t Extent = dynamic_extent>
using device_span = span<T, Extent,
    prop::memory_space<device_memory>, prop::read_write>;

template <typename T, size_t Extent = dynamic_extent>
using device_span_ro = span<T, Extent,
    prop::memory_space<device_memory>, prop::read_only>;

template <typename T, size_t Extent = dynamic_extent>
using host_span = span<T, Extent,
    prop::memory_space<host_memory>, prop::read_write>;

} // namespace world
```

```cpp
// 使用示例 1：ISG（warp）内的个体状态并行同步分片访问
__global__ void tensor_parallel_reduce_kernel(
    world::device_span_ro<float> shard,  // 只读分片视图
    world::device_span<float>    result) // 可写输出
{
    // ISG（warp）内分块：每个 ISG 处理自己的子 span
    int isg_id     = threadIdx.x / warpSize;
    int total_isgs = blockDim.x  / warpSize;
    auto my_shard = shard.isg_partition(isg_id, total_isgs);

    float local_sum = 0.f;
    for (size_t i = 0; i < my_shard.size(); ++i)
        local_sum += my_shard[i];  // 只读访问，编译期保证

    // shard[0] = local_sum;  // 编译错误：read_only span 不允许写入
    result[isg_id] = local_sum;   // OK：result 为 read_write
}

// 使用示例 2：个体间流水线传播（PipelineParallel）阶段边界数据传递
void pipeline_stage_handoff(
    world::device_span<IndividualState> stage_output,   // 上一阶段输出
    world::device_span<IndividualState> stage_input)    // 下一阶段输入（可能重叠）
{
    // 子 span 切片（首 1024 个个体先传播）
    auto priority_batch = stage_output.first<1024>();
    world::async_copy(priority_batch, stage_input.first<1024>(), pipeline_stream);
}

// 编译期错误示例
void compile_time_safety_demo() {
    world::device_vector<float> dev_vec(100);

    // OK: device_vector -> device_span
    world::device_span<float> dspan(dev_vec);

    // ERROR: 尝试从设备向量创建宿主 span（空间不匹配）
    // world::host_span<float> hspan(dev_vec);  // compile error

    // ERROR: 对只读 span 赋值
    // world::device_span_ro<float> ro_span(dev_vec);
    // ro_span[0] = 42.f;  // compile error
}
```

### 与 std::span 的关系

- `world::span` 不继承 `std::span`，避免切片问题
- 提供 `to_std_span()` 显式转换（仅 host_span 可用，设备 span 禁止转换至 std::span）
- 接口命名与 `std::span` 保持一致（`data()`、`size()`、`first()`、`last()`、`subspan()`）

