### 技术复杂度分析

幂运算在自定义浮点类型上的实现分为三个子问题：

1. **浮点幂（pow(x, y)）**：最通用，需通过 `promoted_type` 提升后调用标准 `pow`，再转回，精度受 M/E 位宽约束
2. **整数幂（pow(x, int n)）**：可用快速幂（binary exponentiation）在设备端高效实现，避免 `promoted_type` 的 log/exp 路径
3. **特殊幂次（square, cube, sqrt）**：`sqrt` 单独列为另一 PRD，但 `square`（x²）和 `cube`（x³）应在本 PRD 作为语法糖提供

### 修复后的完整设计

```cpp
namespace world::cmath {

// ─── 1. 通用浮点幂 ───────────────────────────────────────────────
template<int M, int E>
__host__ __device__ inline floating_point<M,E>
pow(floating_point<M,E> base, floating_point<M,E> exp) noexcept {
    using P = typename floating_point<M,E>::promoted_type;
    return static_cast<floating_point<M,E>>(
        ::pow(static_cast<P>(base), static_cast<P>(exp)));
}

// 跨类型：pow(floating_point, float/double/int)
template<int M, int E, typename T,
         typename = std::enable_if_t<std::is_arithmetic_v<T>>>
__host__ __device__ inline floating_point<M,E>
pow(floating_point<M,E> base, T exp) noexcept {
    using P = typename floating_point<M,E>::promoted_type;
    return static_cast<floating_point<M,E>>(
        ::pow(static_cast<P>(base), static_cast<P>(exp)));
}

// ─── 2. 整数幂（快速幂，设备端高效）────────────────────────────
template<int M, int E>
__host__ __device__ inline floating_point<M,E>
powi(floating_point<M,E> base, int n) noexcept {
    if (n == 0) return floating_point<M,E>{1};
    bool neg = (n < 0);
    if (neg) { n = -n; base = floating_point<M,E>{1} / base; }
    floating_point<M,E> result{1};
    while (n > 0) {
        if (n & 1) result = result * base;
        base = base * base;
        n >>= 1;
    }
    return result;
}

// ─── 3. 便利特化 ─────────────────────────────────────────────────
template<int M, int E>
__host__ __device__ inline floating_point<M,E>
square(floating_point<M,E> x) noexcept { return x * x; }

template<int M, int E>
__host__ __device__ inline floating_point<M,E>
cube(floating_point<M,E> x) noexcept { return x * x * x; }

template<int M, int E>
__host__ __device__ inline floating_point<M,E>
pow2(floating_point<M,E> x) noexcept {  // 2^x
    using P = typename floating_point<M,E>::promoted_type;
    return static_cast<floating_point<M,E>>(::exp2(static_cast<P>(x)));
}

} // namespace world::cmath

// 使用示例：
template<int M, int E>
__global__ void energy_decay_kernel(floating_point<M,E>* e, floating_point<M,E> f, int n) {
    using namespace world::cmath;
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < n) e[i] *= pow(f, floating_point<M,E>{2.0f});  // OK
}
```

