## Description

在 pub/sub-loop 世界模型中，`ThreadLoad`（个体线程数据加载原语）是个体状态处理内核（ISK）中最低层的数据读取接口，负责将个体状态从世界全局状态存储（global memory）或个体组共享状态缓存（shared memory）加载到寄存器文件。其正确性和性能直接影响整个世界模型的吞吐量——所有个体的状态读取均通过此路径。

**当前问题**：`ThreadLoad` 的实现存在多个技术债务，包括：代码风格不一致、缓存访问修饰符（Cache Modifier）支持不完整、向量化加载路径（向量化读取，一次加载128bit而非32bit）缺失、以及与现代 CUDA PTX 指令集的对齐问题。这些问题导致编译器无法自动向量化、内存带宽利用率低、以及在不同架构（SM70/SM80/SM90）上行为不一致。

### 当前有问题的代码

```cpp
// 当前 ThreadLoad 实现（简化，显示主要问题）

// 问题1：cache modifier 不完整——缺少 LOAD_LDG（texture cache via __ldg）
enum CacheLoadModifier {
    LOAD_DEFAULT,  // 普通加载
    LOAD_CA,       // L1/L2 缓存
    LOAD_CG,       // L2 only（绕过 L1）
    LOAD_CS,       // streaming（不污染缓存）
    // 缺少：LOAD_LDG（通过 texture 缓存，只读数据最优）
    // 缺少：LOAD_CV（volatile，强制每次从内存读）
    // 缺少：LOAD_NC（non-coherent，通过 texture cache）
};

// 问题2：逐元素加载，未向量化
template<CacheLoadModifier MODIFIER, typename T>
__device__ T ThreadLoad(T* ptr) {
    // 错误：对于 4字节类型，编译器可能生成 LD.E（32bit），
    // 但对于连续的 float4 数组，应使用 LD.E.128（128bit 向量加载）
    // 当前没有向量化特化，导致带宽浪费 4x
    T val;
    asm volatile("ld.global.ca.u32 %0, [%1];" : "=r"(val) : "l"(ptr));
    return val;
    // 问题3：硬编码 .u32，不适配所有 T 类型（float2, float4, int2 等）
}

// 问题4：对齐假设硬编码，未处理非对齐指针
// 个体状态数组有时从奇数偏移开始（复合个体的子体状态切片）

// 用户代码：个体批量状态加载，当前效率低
template<int BLOCK_SIZE, int M, int E>
__device__ void load_individual_states(
    floating_point<M,E>* smem,           // 共享状态缓存
    const floating_point<M,E>* gmem,     // 全局状态存储
    int individual_id)
{
    // 当前：逐元素加载，每次只加载 M+E+1 bits（如16bit）
    // 问题：无法利用 128-bit 向量加载的带宽优势
    smem[threadIdx.x] = ThreadLoad<LOAD_CA>(&gmem[individual_id]);
}
```

### 技术背景：PTX 向量加载与缓存修饰符

CUDA PTX 支持多种加载宽度和缓存策略：

```
PTX 加载指令集：
  ld.global.ca.u32  addr  → 32-bit，L1+L2 缓存
  ld.global.cg.u32  addr  → 32-bit，L2-only
  ld.global.cs.u32  addr  → 32-bit，streaming
  ld.global.lu.u32  addr  → 32-bit，last use（允许缓存驱逐）
  ld.global.nc.u32  addr  → 32-bit，non-coherent（只读路径）

  向量化：
  ld.global.ca.v2.u32  addr  → 64-bit（2×32）
  ld.global.ca.v4.u32  addr  → 128-bit（4×32）← 最优带宽
  ld.global.ca.b128    addr  → 128-bit（单条指令）
```

### 修复后的完整 ThreadLoad 设计

```cpp
// 修复后：完整的 ThreadLoad 实现

// 1. 完整的 CacheLoadModifier 枚举
enum class CacheLoadModifier : uint8_t {
    Default,   // 普通加载（编译器决定）
    CA,        // L1+L2 缓存（读-修改-写友好）
    CG,        // L2 only（大数据集遍历，避免 L1 污染）
    CS,        // Streaming（一次性读取，不缓存）
    LU,        // Last-use（允许缓存驱逐，hint）
    CV,        // Volatile（强制内存读，避免编译器优化）
    LDG,       // 通过 texture 缓存（只读数据最优选择）
    NC,        // Non-coherent（只读，SM80+ 推荐）
};

// 2. PTX 生成辅助：根据 Modifier 和类型生成正确的 PTX 约束
template<CacheLoadModifier MOD, typename T>
struct PtxLoadSelector {
    static constexpr const char* asm_constraint();
    // Default→""，CA→".ca"，CG→".cg"，CS→".cs"，LDG→".nc"（通过 __ldg 内建）
};

// 3. 标量加载（完整修饰符支持）
template<CacheLoadModifier MOD = CacheLoadModifier::Default, typename T>
__device__ __forceinline__ T ThreadLoad(const T* ptr) {
    static_assert(sizeof(T) == 1 || sizeof(T) == 2 || sizeof(T) == 4 || sizeof(T) == 8);

    if constexpr (MOD == CacheLoadModifier::LDG) {
        // __ldg 路径：只读数据通过 texture 缓存
        return __ldg(ptr);
    }

    T val;
    if constexpr (sizeof(T) == 4) {
        asm volatile(
            "ld.global" PtxLoadSelector<MOD,T>::suffix() ".b32 %0, [%1];"
            : "=r"(reinterpret_cast<uint32_t&>(val))
            : "l"(ptr)
        );
    } else if constexpr (sizeof(T) == 8) {
        asm volatile(
            "ld.global" PtxLoadSelector<MOD,T>::suffix() ".b64 %0, [%1];"
            : "=l"(reinterpret_cast<uint64_t&>(val))
            : "l"(ptr)
        );
    }
    // ... 2字节和1字节路径
    return val;
}

// 4. 向量化加载特化（128-bit，最高带宽）
template<CacheLoadModifier MOD = CacheLoadModifier::Default>
__device__ __forceinline__ float4 ThreadLoad(const float4* ptr) {
    float4 val;
    asm volatile(
        "ld.global" PtxLoadSelector<MOD,float4>::suffix() ".v4.f32 {%0,%1,%2,%3}, [%4];"
        : "=f"(val.x), "=f"(val.y), "=f"(val.z), "=f"(val.w)
        : "l"(ptr)
    );
    return val;
}

// 5. 个体批量状态加载：利用向量化
template<int BLOCK_SIZE>
__device__ void load_fp16_individual_states_vectorized(
    uint16_t* smem, const uint16_t* gmem, int base_id)
{
    // 每次加载 8个 fp16（128-bit），而非逐个加载
    // 需要 base_id 按 8 对齐
    if ((base_id & 7) == 0) {
        auto* src = reinterpret_cast<const uint4*>(gmem + base_id);
        auto* dst = reinterpret_cast<uint4*>(smem + threadIdx.x * 8);
        *dst = ThreadLoad<CacheLoadModifier::LDG>(src);  // 128-bit，texture cache
    }
}
```

