## Description

The current `IndividualSegmentedReduce` implementation for `ArgMin` and `ArgMax` operations uses 32-bit signed integers (`int32_t`) to represent item indices and segment offsets internally. This mirrors the historical limitation in NVIDIA CUB's `DeviceSegmentedReduce` where `num_items` was silently truncated when the total item count across all segments exceeded `INT32_MAX` (2,147,483,647 items).

In the pub/sub-loop world model, segmented reduction over individuals is critical for operations such as: finding the individual with minimum belief-state entropy within each spatial grid cell (ArgMin over segments = grid cells), or finding the highest-priority individual in each ISG (ArgMax over ISG segments). As world scales increase—particularly in large-scale multi-agent simulations where millions of particle individuals are tracked across thousands of spatial segments—the 32-bit limit becomes a hard wall.

**The failure mode is silent corruption, not a crash.** When `num_items > INT32_MAX`, the internal index computation wraps around silently, returning wrong ArgMin/ArgMax indices. An autonomous vehicle individual querying "which perception sub-body has the lowest uncertainty?" could silently receive a wrong index, causing catastrophic planning errors with no error signal.

**Affected scenario:** A city-scale traffic simulation world with:
- 50,000 vehicle individuals, each with 64 particle sub-bodies = 3,200,000 particle states
- Divided into 1,000 spatial grid segments
- ArgMin per segment for minimum-entropy particle selection
- Total `num_items` = 3.2M (safe), but projected scale of 100,000 vehicles × 64 = 6.4M still safe
- At 500,000 vehicles × 64 sub-bodies = 32M → still safe, but 1M vehicles × 256 sub-bodies = 256M approaches limit in 18 months

**Current broken implementation:**
```cpp
// CURRENT: 32-bit index arithmetic — silent overflow for large worlds
template<typename InputIteratorT, typename OffsetIteratorT>
struct SegmentedArgMinKernel {
    __device__ void reduce_segment(
        InputIteratorT d_in,
        int32_t segment_begin,   // BUG: 32-bit — wraps at 2.1B
        int32_t segment_end,
        KeyValuePair<int32_t, float>& result
    ) {
        KeyValuePair<int32_t, float> local_min{INT32_MAX, FLT_MAX};
        // int32_t arithmetic — overflow when segment_begin > INT32_MAX
        for (int32_t i = segment_begin; i < segment_end; ++i) {
            float val = d_in[i];
            if (val < local_min.value) {
                local_min = {i, val};  // index stored as int32 — truncated!
            }
        }
        result = local_min;
    }
};
```

**Fixed implementation with 64-bit index support:**
```cpp
// NEW: 64-bit aware IndividualSegmentedArgReduce
#include <world/collection/segmented_reduce.hpp>

namespace world::collection {

// 64-bit capable KeyValue pair for large world index spaces
template<typename IndexT, typename ValueT>
struct IndividualKeyValue {
    IndexT  individual_index;  // int64_t for large worlds
    ValueT  state_value;

    __host__ __device__ bool operator<(const IndividualKeyValue& other) const {
        return state_value < other.state_value;
    }
};

// Dispatch tag for index width selection
struct LargeWorldTag {};   // num_items > INT32_MAX
struct SmallWorldTag {};   // num_items <= INT32_MAX (fast path)

template<
    typename InputIteratorT,
    typename OffsetIteratorT,
    typename OutputIteratorT,
    typename IndexT = int64_t  // default to 64-bit for safety
>
struct IndividualSegmentedArgMin {

    // Auto-dispatch based on actual num_items
    static cudaError_t dispatch(
        void*            d_temp_storage,
        size_t&          temp_storage_bytes,
        InputIteratorT   d_in,
        OutputIteratorT  d_out,
        int              num_segments,
        OffsetIteratorT  d_begin_offsets,
        OffsetIteratorT  d_end_offsets,
        int64_t          num_items,       // Changed: int64_t instead of int
        cudaStream_t     stream = nullptr
    ) {
        if (num_items > INT32_MAX) {
            return dispatch_impl<int64_t, LargeWorldTag>(
                d_temp_storage, temp_storage_bytes, d_in, d_out,
                num_segments, d_begin_offsets, d_end_offsets, num_items, stream
            );
        } else {
            return dispatch_impl<int32_t, SmallWorldTag>(
                d_temp_storage, temp_storage_bytes, d_in, d_out,
                num_segments, d_begin_offsets, d_end_offsets, 
                static_cast<int32_t>(num_items), stream
            );
        }
    }

private:
    template<typename ActiveIndexT, typename DispatchTag>
    static cudaError_t dispatch_impl(/* ... */);
};

// Similarly for ArgMax
template<typename InputIteratorT, typename OffsetIteratorT, typename OutputIteratorT, typename IndexT = int64_t>
struct IndividualSegmentedArgMax { /* symmetric implementation */ };

} // namespace world::collection

// Usage example: find minimum-entropy particle per spatial cell
void find_min_entropy_particles(
    float*   d_particle_entropies,    // [num_particles] entropy values
    int64_t  num_particles,           // may exceed INT32_MAX in large worlds
    int64_t* d_cell_begin,            // segment begin offsets (64-bit)
    int64_t* d_cell_end,              // segment end offsets (64-bit)
    int      num_cells,
    IndividualKeyValue<int64_t, float>* d_argmin_results
) {
    void*  d_temp = nullptr;
    size_t temp_bytes = 0;

    // First pass: determine temp storage
    world::collection::IndividualSegmentedArgMin<>::dispatch(
        nullptr, temp_bytes,
        d_particle_entropies, d_argmin_results,
        num_cells, d_cell_begin, d_cell_end,
        num_particles
    );

    cudaMalloc(&d_temp, temp_bytes);

    // Second pass: compute
    world::collection::IndividualSegmentedArgMin<>::dispatch(
        d_temp, temp_bytes,
        d_particle_entropies, d_argmin_results,
        num_cells, d_cell_begin, d_cell_end,
        num_particles
    );
}
```

