WorldError individual_fill_initialized(
    IndividualT*              d_individuals,
    size_t                    n,
    IndividualInitializer<IndividualT> init,
    WorldStream               stream = WorldStream::default_stream()
);

// IndividualInitializer: callable that constructs a valid initial state
template<typename IndividualT>
struct IndividualInitializer {
    __device__ IndividualT operator()(size_t index) const;
};

} // namespace world::parallel

// Example: episode reset with typed initializer
struct VehicleIndividualInit {
    float3* d_spawn_positions;  // per-individual spawn points

    __device__ VehicleIndividual operator()(size_t idx) const {
        VehicleIndividual vi;
        vi.position      = d_spawn_positions[idx];
        vi.velocity      = float3{0.0f, 0.0f, 0.0f};
